6	
7	------------------------------------------------------------------------------
8	-- Description
9	------------------------------------------------------------------------------
10	-- This entity implements a full AXI-4 slave for simple IP-Core interfaces. It
11	-- supports the implementation of registers as well as access to memories.
12	-- Its only main limitations are, that data for memory accesses must be available for
13	-- reading after one clock cycle. So except using a synchronous RAM, no additional
14	-- pipelining is possible and that it only supports 32-bit wide AXI bus.
15	
16	library ieee;
17	use ieee.std_logic_1164.all;
18	use ieee.numeric_std.all;
19	
20	use work.psi_common_array_pkg.all;
21	use work.psi_common_math_pkg.all;
22	use work.psi_common_logic_pkg.all;
23	--@fomratter:off
24	entity psi_common_axi_slave_ipif is
25	  generic(
26	    -- IP Interface Config
27	    num_reg_g        : integer  := 32;                      -- Number of registers to implement
28	    rst_val_g        : t_aslv32 := (0 => (others => '0'));  -- Reset values for registers. The size of the array passed does not have to match NumReg_g, if it does not, the reset values are applied to the first N registers and the other registers are reset to zero.
29	    use_mem_g        : boolean  := true;                    -- **True** = use memory interface, **False** = use registers only
30	    -- AXI Config
31	    axi_id_width_g   : integer  := 1;                       -- Number of bits used for the AXI ID signals
32	    axi_addr_width_g : integer  := 8                        -- Number of AXI address bits supported
33	  );
34	  port(
35	    -- System
36	    s_axi_aclk    : in  std_logic;                                        -- system clock
37	    s_axi_aresetn : in  std_logic;                                        -- system reset active low
38	    -- Read address channel
39	    s_axi_arid    : in  std_logic_vector(axi_id_width_g - 1 downto 0);
40	    s_axi_araddr  : in  std_logic_vector(axi_addr_width_g - 1 downto 0);
41	    s_axi_arlen   : in  std_logic_vector(7 downto 0);
42	    s_axi_arsize  : in  std_logic_vector(2 downto 0);
43	    s_axi_arburst : in  std_logic_vector(1 downto 0);
44	    s_axi_arlock  : in  std_logic;
45	    s_axi_arcache : in  std_logic_vector(3 downto 0);
46	    s_axi_arprot  : in  std_logic_vector(2 downto 0);
47	    s_axi_arvalid : in  std_logic;
48	    s_axi_arready : out std_logic;
49	    -- Read data channel
50	    s_axi_rid     : out std_logic_vector(axi_id_width_g - 1 downto 0);
51	    s_axi_rdata   : out std_logic_vector(31 downto 0);
52	    s_axi_rresp   : out std_logic_vector(1 downto 0);
53	    s_axi_rlast   : out std_logic;
54	    s_axi_rvalid  : out std_logic;
55	    s_axi_rready  : in  std_logic;
56	    -- Write address channel
57	    s_axi_awid    : in  std_logic_vector(axi_id_width_g - 1 downto 0);
58	    s_axi_awaddr  : in  std_logic_vector(axi_addr_width_g - 1 downto 0);
59	    s_axi_awlen   : in  std_logic_vector(7 downto 0);
60	    s_axi_awsize  : in  std_logic_vector(2 downto 0);
61	    s_axi_awburst : in  std_logic_vector(1 downto 0);
62	    s_axi_awlock  : in  std_logic;
63	    s_axi_awcache : in  std_logic_vector(3 downto 0);
64	    s_axi_awprot  : in  std_logic_vector(2 downto 0);
65	    s_axi_awvalid : in  std_logic;
66	    s_axi_awready : out std_logic;
67	    -- Write data channel
68	    s_axi_wdata   : in  std_logic_vector(31 downto 0);
69	    s_axi_wstrb   : in  std_logic_vector(3 downto 0);
70	    s_axi_wlast   : in  std_logic;
71	    s_axi_wvalid  : in  std_logic;
72	    s_axi_wready  : out std_logic;
73	    -- Write response channel
74	    s_axi_bid     : out std_logic_vector(axi_id_width_g - 1 downto 0);
75	    s_axi_bresp   : out std_logic_vector(1 downto 0);
76	    s_axi_bvalid  : out std_logic;
77	    s_axi_bready  : in  std_logic;
78	    -- Register Interface
79	    o_reg_rd      : out std_logic_vector(num_reg_g - 1 downto 0);                     -- Read-pulse for each register
80	    i_reg_rdata   : in  t_aslv32(0 to num_reg_g - 1)  := (others => (others => '0')); -- Register read values
81	    o_reg_wr      : out std_logic_vector(num_reg_g - 1 downto 0);                     -- Write-pulse for each register
82	    o_reg_wdata   : out t_aslv32(0 to num_reg_g - 1);                                 -- Register write values
83	    -- Memory Interface
84	    o_mem_addr    : out std_logic_vector(axi_addr_width_g - 1 downto 0);  -- Memory address
85	    o_mem_wr      : out std_logic_vector(3 downto 0);                     -- Memory byte write enables (one signal per byte)
86	    o_mem_wdata   : out std_logic_vector(31 downto 0);                    -- Memory write data
87	    i_mem_rdata   : in  std_logic_vector(31 downto 0) := (others => '0')  -- Memory read data must be valid one clock cycle after o_mem_addr
88	
89	  );
90	end entity;
91	--@fomratter:on
92	architecture behav of psi_common_axi_slave_ipif is
93	  -----------------------------------------------------------------------------
94	  -- AXI slave bus interface
95	  -----------------------------------------------------------------------------
96	  type axi_fsm_type is (
97	    axi_fsm_idle,
98	    axi_fsm_rd_data,
99	    axi_fsm_wr_data,
100	    axi_fsm_wr_resp_delay,
101	    axi_fsm_wr_done);
102	  signal axi_fsm_comb          : axi_fsm_type;
103	  signal axi_fsm               : axi_fsm_type;
104	  -- ADDR_INDEX_LOW is used for addressing 32/64 bit registers/memories
105	  -- ADDR_INDEX_LOW = 2 for 32 bits (n downto 2)
106	  -- ADDR_INDEX_LOW = 3 for 64 bits (n downto 3)
107	  constant REG_ADDR_INDEX_LOW  : integer                                       := 2;
108	  constant REG_ADDR_WIDTH      : integer                                       := integer(log2ceil(num_reg_g)) + REG_ADDR_INDEX_LOW;
109	  constant REG_ADDR_INDEX_HIGH : integer                                       := REG_ADDR_WIDTH - 1;
110	  constant MEM_ADDR_START      : unsigned(axi_addr_width_g - 1 downto 0)       := to_unsigned(2**(REG_ADDR_WIDTH), axi_addr_width_g);
111	  constant RESP_OKAY_c         : std_logic_vector(1 downto 0)                  := "00";
112	  constant RESP_EXOKAY_c       : std_logic_vector(1 downto 0)                  := "01";
113	  constant RESP_SLVERR_c       : std_logic_vector(1 downto 0)                  := "10";
114	  constant RESP_DECERR_c       : std_logic_vector(1 downto 0)                  := "11";
115	  -- Read address channel
116	  signal axi_arid              : std_logic_vector(axi_id_width_g - 1 downto 0) := (others => '0');
117	  signal axi_araddr            : unsigned(axi_addr_width_g - 1 downto 0)       := (others => '0');
118	  signal axi_araddr_last       : unsigned(axi_addr_width_g - 1 downto 0)       := (others => '0');
119	  signal axi_arlen             : unsigned(7 downto 0)                          := (others => '0');
120	  signal axi_arsize            : unsigned(axi_addr_width_g - 1 downto 0)       := (others => '0');
121	  signal axi_arburst           : std_logic_vector(1 downto 0)                  := (others => '0');
122	  signal axi_arwrap_en         : std_logic                                     := '0';
123	  signal axi_arwrap            : unsigned(axi_addr_width_g - 1 downto 0)       := (others => '0');
124	  -- Read data channel
125	  signal axi_rresp             : std_logic_vector(1 downto 0);
126	  signal axi_rlast             : std_logic                                     := '0';
127	  signal axi_rready            : std_logic                                     := '0';
128	  signal axi_rvalid            : std_logic                                     := '0';
129	  -- Write address channel
130	  signal axi_awid              : std_logic_vector(axi_id_width_g - 1 downto 0) := (others => '0');
131	  signal axi_awaddr            : unsigned(axi_addr_width_g - 1 downto 0)       := (others => '0');
132	  signal axi_awlen             : unsigned(7 downto 0)                          := (others => '0');
133	  signal axi_awsize            : unsigned(axi_addr_width_g - 1 downto 0)       := (others => '0');
134	  signal axi_awburst           : std_logic_vector(1 downto 0)                  := (others => '0');
135	  signal axi_awwrap_en         : std_logic                                     := '0';
136	  signal axi_awwrap            : unsigned(axi_addr_width_g - 1 downto 0)       := (others => '0');
137	  -- Write data channel
138	  signal axi_wlast             : std_logic                                     := '0';
139	  signal axi_wready            : std_logic                                     := '0';
140	  -- Write response channel
141	  signal axi_bresp             : std_logic_vector(1 downto 0);
142	  -- Derived signals
143	  signal axi_raddr_sel         : std_logic                                     := '0';
144	  signal axi_waddr_sel         : std_logic                                     := '0';
145	  signal reg_rd                : std_logic_vector(num_reg_g - 1 downto 0)      := (others => '0');
146	  signal reg_wr                : std_logic_vector(num_reg_g - 1 downto 0)      := (others => '0');
147	  signal reg_rdata             : std_logic_vector(31 downto 0)                 := (others => '0');
148	  signal reg_rvalid            : std_logic                                     := '0';
149	  signal mem_rvalid            : std_logic                                     := '0';
150	  -- R-channel pipeline stage
151	  signal rpl_rready            : std_logic;
152	  signal rpl_rvalid            : std_logic;
153	  signal rpl_rid               : std_logic_vector(axi_id_width_g - 1 downto 0);
154	  signal rpl_rdata             : std_logic_vector(31 downto 0);
155	  signal rpl_rresp             : std_logic_vector(1 downto 0);
156	  signal rpl_rlast             : std_logic;
157	
158	begin
159	
160	  -----------------------------------------------------------------------------
161	  -- Assertions
162	  -----------------------------------------------------------------------------
163	  assert isLog2(num_reg_g) report "###ERROR###: psi_common_axi_slave_ipif: num_reg_g must be a power of two!" severity error;
164	  assert not (not use_mem_g and num_reg_g = 0) report "###ERROR###: psi_common_axi_slave_ipif: num_reg_g must be > 0 if use_mem_g = true" severity error;
165	
166	  -----------------------------------------------------------------------------
167	  -- AXI fsm
168	  -----------------------------------------------------------------------------
169	  axi_fsm_comb_proc : process(axi_fsm, axi_rlast, axi_wlast, s_axi_aresetn, s_axi_arvalid, s_axi_awvalid, s_axi_bready, rpl_rready, s_axi_wvalid)
170	  begin
171	    if (s_axi_aresetn = '0') then
172	      axi_fsm_comb <= axi_fsm_idle;
173	    else
174	      axi_fsm_comb <= axi_fsm;
175	      case axi_fsm is
176	        when axi_fsm_idle =>
177	          if (s_axi_arvalid = '1') then
178	            axi_fsm_comb <= axi_fsm_rd_data;
179	          elsif (s_axi_awvalid = '1') then
180	            axi_fsm_comb <= axi_fsm_wr_data;
181	          end if;
182	        when axi_fsm_rd_data =>
183	          if ((axi_rlast = '1') and (rpl_rready = '1')) then
184	            axi_fsm_comb <= axi_fsm_idle;
185	          end if;
186	        when axi_fsm_wr_data =>
187	          if ((axi_wlast = '1') and (s_axi_wvalid = '1')) then
188	            axi_fsm_comb <= axi_fsm_wr_resp_delay;
189	          end if;
190	        when axi_fsm_wr_resp_delay =>
191	          axi_fsm_comb <= axi_fsm_wr_done;
192	        when axi_fsm_wr_done =>
193	          if (s_axi_bready = '1') then
194	            axi_fsm_comb <= axi_fsm_idle;
195	          end if;
196	        when others =>
197	          axi_fsm_comb <= axi_fsm_idle;
198	      end case;
199	    end if;
200	  end process;
201	
202	  axi_fsm_proc : process(s_axi_aclk)
203	  begin
204	    if rising_edge(s_axi_aclk) then
205	      axi_fsm <= axi_fsm_comb;
206	    end if;
207	  end process axi_fsm_proc;
208	
209	  -----------------------------------------------------------------------------
210	  -- AXI ARADDR
211	  -----------------------------------------------------------------------------
212	  axi_arwrap_en <= '1' when ((axi_araddr and axi_arwrap) = axi_arwrap) else '0';
213	
214	  axi_araddr_proc : process(s_axi_aclk)
215	  begin
216	    if rising_edge(s_axi_aclk) then
217	      case axi_fsm is
218	        when axi_fsm_idle =>
219	          axi_rresp <= RESP_OKAY_c;
220	          if (axi_fsm_comb = axi_fsm_rd_data) then
221	            axi_araddr      <= unsigned(s_axi_araddr);
222	            axi_araddr_last <= unsigned(s_axi_araddr);
223	            case (s_axi_arsize) is
224	              when "000" =>
225	                axi_arsize <= to_unsigned(1, axi_addr_width_g);
226	              when "001" =>
227	                axi_arsize <= to_unsigned(2, axi_addr_width_g);
228	              when "010" =>
229	                axi_arsize <= to_unsigned(4, axi_addr_width_g);
230	              when others =>
231	                axi_arsize <= to_unsigned(1, axi_addr_width_g);
232	            end case;
233	            axi_arburst     <= s_axi_arburst;
234	            axi_arlen       <= unsigned(s_axi_arlen);
235	            if (s_axi_arburst = "10") then -- If wrapping burst
236	              case (s_axi_arlen) is
237	                when X"01" =>
238	                  case (s_axi_arsize) is
239	                    when "000" =>
240	                      axi_arwrap <= to_unsigned(2 * 1 - 1, axi_addr_width_g);
241	                    when "001" =>
242	                      axi_arwrap <= to_unsigned(2 * 2 - 1, axi_addr_width_g);
243	                    when "010" =>
244	                      axi_arwrap <= to_unsigned(2 * 4 - 1, axi_addr_width_g);
245	                    when others =>
246	                      axi_arwrap <= to_unsigned(2 * 1 - 1, axi_addr_width_g);
247	                  end case;
248	                when X"03" =>
249	                  case (s_axi_arsize) is
250	                    when "000" =>
251	                      axi_arwrap <= to_unsigned(4 * 1 - 1, axi_addr_width_g);
252	                    when "001" =>
253	                      axi_arwrap <= to_unsigned(4 * 2 - 1, axi_addr_width_g);
254	                    when "010" =>
255	                      axi_arwrap <= to_unsigned(4 * 4 - 1, axi_addr_width_g);
256	                    when others =>
257	                      axi_arwrap <= to_unsigned(4 * 1 - 1, axi_addr_width_g);
258	                  end case;
259	                when X"07" =>
260	                  case (s_axi_arsize) is
261	                    when "000" =>
262	                      axi_arwrap <= to_unsigned(8 * 1 - 1, axi_addr_width_g);
263	                    when "001" =>
264	                      axi_arwrap <= to_unsigned(8 * 2 - 1, axi_addr_width_g);
265	                    when "010" =>
266	                      axi_arwrap <= to_unsigned(8 * 4 - 1, axi_addr_width_g);
267	                    when others =>
268	                      axi_arwrap <= to_unsigned(8 * 1 - 1, axi_addr_width_g);
269	                  end case;
270	                when X"0F" =>
271	                  case (s_axi_arsize) is
272	                    when "000" =>
273	                      axi_arwrap <= to_unsigned(16 * 1 - 1, axi_addr_width_g);
274	                    when "001" =>
275	                      axi_arwrap <= to_unsigned(16 * 2 - 1, axi_addr_width_g);
276	                    when "010" =>
277	                      axi_arwrap <= to_unsigned(16 * 4 - 1, axi_addr_width_g);
278	                    when others =>
279	                      axi_arwrap <= to_unsigned(16 * 1 - 1, axi_addr_width_g);
280	                  end case;
281	                when others =>
282	                  axi_arwrap <= to_unsigned(2 * 1 - 1, axi_addr_width_g);
283	              end case;
284	            end if;
285	          end if;
286	        when axi_fsm_rd_data =>
287	          -- Produce decoding error if memory is accessed but not enabled
288	          if unsigned(axi_araddr) >= (num_reg_g * 4) and not use_mem_g then
289	            axi_rresp <= RESP_DECERR_c;
290	          end if;
291	          -- Do access
292	          if (rpl_rready = '1') then
293	            case (axi_arburst) is
294	              when "00" =>              -- Fixed burst
295	                null;
296	              when "01" =>              -- Incremental burst
297	                axi_araddr <= axi_araddr + axi_arsize;
298	              when "10" =>              -- Wrapping burst
299	                if (axi_arwrap_en = '1') then
300	                  axi_araddr <= axi_araddr - axi_arwrap;
301	                else
302	                  axi_araddr <= axi_araddr + axi_arsize;
303	                end if;
304	              when others =>            -- Reserved
305	                null;
306	            end case;
307	            axi_araddr_last <= axi_araddr;
308	          else
309	            axi_araddr <= axi_araddr_last;
310	          end if;
311	          if (axi_rvalid = '1') then
312	            axi_arlen <= axi_arlen - 1;
313	          end if;
314	        when others =>
315	          null;
316	      end case;
317	    end if;
318	  end process axi_araddr_proc;
319	
320	  -----------------------------------------------------------------------------
321	  -- AXI RADDR denotes register or memory
322	  -----------------------------------------------------------------------------
323	  axi_raddr_sel <= '1' when ((axi_fsm = axi_fsm_rd_data) and (to_integer(unsigned(axi_araddr_last(axi_addr_width_g - 1 downto REG_ADDR_WIDTH))) /= 0)) else '0';
324	
325	  -----------------------------------------------------------------------------
326	  -- AXI ARREADY
327	  -----------------------------------------------------------------------------
328	  s_axi_arready <= '1' when ((axi_fsm = axi_fsm_idle) and (axi_fsm_comb = axi_fsm_rd_data)) else '0';
329	
330	  -----------------------------------------------------------------------------
331	  -- AXI RID
332	  -----------------------------------------------------------------------------
333	  axi_rid_proc : process(s_axi_aclk)
334	  begin
335	    if rising_edge(s_axi_aclk) then
336	      if (axi_fsm = axi_fsm_idle) then
337	        if (axi_fsm_comb = axi_fsm_rd_data) then
338	          axi_arid <= s_axi_arid;
339	        else
340	          axi_arid <= (others => '0');
341	        end if;
342	      end if;
343	    end if;
344	  end process axi_rid_proc;
345	
346	  rpl_rid <= axi_arid;
347	
348	  -----------------------------------------------------------------------------
349	  -- AXI RREADY
350	  -----------------------------------------------------------------------------
351	  axi_rready_proc : process(s_axi_aclk)
352	  begin
353	    if rising_edge(s_axi_aclk) then
354	      if (axi_fsm = axi_fsm_rd_data) then
355	        axi_rready <= rpl_rready;
356	      else
357	        axi_rready <= '0';
358	      end if;
359	    end if;
360	  end process axi_rready_proc;
361	
362	  -----------------------------------------------------------------------------
363	  -- AXI RVALID
364	  -----------------------------------------------------------------------------
365	  axi_rvalid <= reg_rvalid or mem_rvalid;
366	  rpl_rvalid <= axi_rvalid;
367	
368	  -----------------------------------------------------------------------------
369	  -- AXI RLAST
370	  -----------------------------------------------------------------------------
371	  axi_rlast <= '1' when (((mem_rvalid = '1') or (reg_rvalid = '1')) and (axi_arlen = X"00")) else '0';
372	  rpl_rlast <= axi_rlast;
373	
374	  -----------------------------------------------------------------------------
375	  -- AXI RRESP
376	  -----------------------------------------------------------------------------
377	  rpl_rresp <= axi_rresp;
378	
379	  -----------------------------------------------------------------------------
380	  -- AXI AWADDR
381	  -----------------------------------------------------------------------------
382	  axi_awwrap_en <= '1' when ((axi_awaddr and axi_awwrap) = axi_awwrap) else '0';
383	
384	  axi_awaddr_proc : process(s_axi_aclk)
385	  begin
386	    if rising_edge(s_axi_aclk) then
387	      case axi_fsm is
388	        when axi_fsm_idle =>
389	          axi_bresp <= RESP_OKAY_c;
390	          if (axi_fsm_comb = axi_fsm_wr_data) then
391	            axi_awaddr  <= unsigned(s_axi_awaddr);
392	            case (s_axi_awsize) is
393	              when "000" =>
394	                axi_awsize <= to_unsigned(1, axi_addr_width_g);
395	              when "001" =>
396	                axi_awsize <= to_unsigned(2, axi_addr_width_g);
397	              when "010" =>
398	                axi_awsize <= to_unsigned(4, axi_addr_width_g);
399	              when others =>
400	                axi_awsize <= to_unsigned(1, axi_addr_width_g);
401	            end case;
402	            axi_awburst <= s_axi_awburst;
403	            axi_awlen   <= unsigned(s_axi_awlen);
404	            if (s_axi_awburst = "10") then -- If wrapping burst
405	              case (s_axi_awlen) is
406	                when X"01" =>
407	                  case (s_axi_awsize) is
408	                    when "000" =>
409	                      axi_awwrap <= to_unsigned(2 * 1 - 1, axi_addr_width_g);
410	                    when "001" =>
411	                      axi_awwrap <= to_unsigned(2 * 2 - 1, axi_addr_width_g);
412	                    when "010" =>
413	                      axi_awwrap <= to_unsigned(2 * 4 - 1, axi_addr_width_g);
414	                    when others =>
415	                      axi_awwrap <= to_unsigned(2 * 1 - 1, axi_addr_width_g);
416	                  end case;
417	                when X"03" =>
418	                  case (s_axi_awsize) is
419	                    when "000" =>
420	                      axi_awwrap <= to_unsigned(4 * 1 - 1, axi_addr_width_g);
421	                    when "001" =>
422	                      axi_awwrap <= to_unsigned(4 * 2 - 1, axi_addr_width_g);
423	                    when "010" =>
424	                      axi_awwrap <= to_unsigned(4 * 4 - 1, axi_addr_width_g);
425	                    when others =>
426	                      axi_awwrap <= to_unsigned(4 * 1 - 1, axi_addr_width_g);
427	                  end case;
428	                when X"07" =>
429	                  case (s_axi_awsize) is
430	                    when "000" =>
431	                      axi_awwrap <= to_unsigned(8 * 1 - 1, axi_addr_width_g);
432	                    when "001" =>
433	                      axi_awwrap <= to_unsigned(8 * 2 - 1, axi_addr_width_g);
434	                    when "010" =>
435	                      axi_awwrap <= to_unsigned(8 * 4 - 1, axi_addr_width_g);
436	                    when others =>
437	                      axi_awwrap <= to_unsigned(8 * 1 - 1, axi_addr_width_g);
438	                  end case;
439	                when X"0F" =>
440	                  case (s_axi_awsize) is
441	                    when "000" =>
442	                      axi_awwrap <= to_unsigned(16 * 1 - 1, axi_addr_width_g);
443	                    when "001" =>
444	                      axi_awwrap <= to_unsigned(16 * 2 - 1, axi_addr_width_g);
445	                    when "010" =>
446	                      axi_awwrap <= to_unsigned(16 * 4 - 1, axi_addr_width_g);
447	                    when others =>
448	                      axi_awwrap <= to_unsigned(16 * 1 - 1, axi_addr_width_g);
449	                  end case;
450	                when others =>
451	                  axi_awwrap <= to_unsigned(2 * 1 - 1, axi_addr_width_g);
452	              end case;
453	            end if;
454	          end if;
455	        when axi_fsm_wr_data =>
456	          -- Produce decoding error if memory is accessed but not enabled
457	          if unsigned(axi_awaddr) >= (num_reg_g * 4) and not use_mem_g then
458	            axi_bresp <= RESP_DECERR_c;
459	          end if;
460	          -- Do access
461	          if (s_axi_wvalid = '1') then
462	            case (axi_awburst) is
463	              when "00" =>              -- Fixed burst
464	                null;
465	              when "01" =>              -- Incremental burst
466	                axi_awaddr <= axi_awaddr + axi_awsize;
467	              when "10" =>              -- Wrapping burst
468	                if (axi_awwrap_en = '1') then
469	                  axi_awaddr <= axi_awaddr - axi_awwrap;
470	                else
471	                  axi_awaddr <= axi_awaddr + axi_awsize;
472	                end if;
473	              when others =>            -- Reserved
474	                null;
475	            end case;
476	          end if;
477	          if (axi_wready = '1') then
478	            axi_awlen <= axi_awlen - 1;
479	          end if;
480	        when others =>
481	          null;
482	      end case;
483	    end if;
484	  end process axi_awaddr_proc;
485	
486	  -----------------------------------------------------------------------------
487	  -- AXI WADDR denotes register or memory
488	  -----------------------------------------------------------------------------
489	  axi_waddr_sel <= '1' when ((axi_fsm = axi_fsm_wr_data) and (to_integer(unsigned(axi_awaddr(axi_addr_width_g - 1 downto REG_ADDR_WIDTH))) /= 0)) else '0';
490	
491	  -----------------------------------------------------------------------------
492	  -- AXI AWREADY
493	  -----------------------------------------------------------------------------
494	  s_axi_awready <= '1' when ((axi_fsm = axi_fsm_idle) and (axi_fsm_comb = axi_fsm_wr_data)) else '0';
495	
496	  -----------------------------------------------------------------------------
497	  -- AXI WID
498	  -----------------------------------------------------------------------------
499	  axi_wid_proc : process(s_axi_aclk)
500	  begin
501	    if rising_edge(s_axi_aclk) then
502	      if (axi_fsm = axi_fsm_idle) then
503	        if (axi_fsm_comb = axi_fsm_wr_data) then
504	          axi_awid <= s_axi_awid;
505	        else
506	          axi_awid <= (others => '0');
507	        end if;
508	      end if;
509	    end if;
510	  end process axi_wid_proc;
511	
512	  s_axi_bid <= axi_awid;
513	
514	  -----------------------------------------------------------------------------
515	  -- AXI WREADY
516	  -----------------------------------------------------------------------------
517	  axi_wready   <= '1' when ((axi_fsm = axi_fsm_wr_data) and (s_axi_wvalid = '1')) else '0';
518	  s_axi_wready <= axi_wready;
519	
520	  -----------------------------------------------------------------------------
521	  -- AXI WLAST
522	  -----------------------------------------------------------------------------
523	  axi_wlast <= '1' when ((axi_wready = '1') and (axi_awlen = X"00")) else '0';
524	
525	  -----------------------------------------------------------------------------
526	  -- AXI BRESP
527	  -----------------------------------------------------------------------------
528	  s_axi_bresp <= axi_bresp;
529	
530	  -----------------------------------------------------------------------------
531	  -- AXI BVALID
532	  -----------------------------------------------------------------------------
533	  s_axi_bvalid <= '1' when (axi_fsm = axi_fsm_wr_done) else '0';
534	
535	  ---------------------------------------------------------------------------
536	  -- IP to Bus data
537	  ---------------------------------------------------------------------------
538	  rpl_rdata <= reg_rdata when (reg_rvalid = '1')
539	               else i_mem_rdata when (mem_rvalid = '1' and use_mem_g)
540	               else (others => '0');
541	
542	  ---------------------------------------------------------------------------
543	  -- Register read
544	  ---------------------------------------------------------------------------
545	  reg_rvalid <= '1' when ((axi_raddr_sel = '0') and (axi_fsm = axi_fsm_rd_data) and (axi_rready = '1') and (rpl_rready = '1')) else '0';
546	
547	  b_rdreg : block
548	    signal rd_data_ext : t_aslv32(0 to num_reg_g + 1) := (others => (others => '0'));
549	  begin
550	    rd_data_ext(0 to i_reg_rdata'high) <= i_reg_rdata; -- extend number of registers to prevent indexing errors
551	    reg_rdata_proc : process(s_axi_aclk) is
552	    begin
553	      if rising_edge(s_axi_aclk) then
554	        reg_rdata(31 downto 0) <= rd_data_ext(to_integer(unsigned(axi_araddr(REG_ADDR_INDEX_HIGH downto REG_ADDR_INDEX_LOW))));
555	      end if;
556	    end process reg_rdata_proc;
557	  end block;
558	
559	  reg_rd_proc : process(s_axi_aclk) is
560	  begin
561	    if rising_edge(s_axi_aclk) then
562	      if (s_axi_aresetn = '0') then
563	        reg_rd <= (others => '0');
564	      else
565	        reg_rd <= (others => '0');
566	        if (reg_rvalid = '1') then
567	          reg_rd(to_integer(unsigned(axi_araddr_last(REG_ADDR_INDEX_HIGH downto REG_ADDR_INDEX_LOW)))) <= '1';
568	        end if;
569	      end if;
570	    end if;
571	  end process reg_rd_proc;
572	
573	  o_reg_rd <= reg_rd;
574	
575	  ---------------------------------------------------------------------------
576	  -- Register write
577	  ---------------------------------------------------------------------------
578	  reg_wr_proc : process(s_axi_aclk) is
579	  begin
580	    if rising_edge(s_axi_aclk) then
581	      if (s_axi_aresetn = '0') then
582	        reg_wr <= (others => '0');
583	      else
584	        reg_wr <= (others => '0');
585	        if ((axi_waddr_sel = '0') and (axi_wready = '1')) then
586	          reg_wr(to_integer(unsigned(axi_awaddr(REG_ADDR_INDEX_HIGH downto REG_ADDR_INDEX_LOW)))) <= '1';
587	        end if;
588	      end if;
589	    end if;
590	  end process reg_wr_proc;
591	
592	  o_reg_wr <= reg_wr;
593	
594	  slv_reg_wr_proc : process(s_axi_aclk) is
595	  begin
596	    if rising_edge(s_axi_aclk) then
597	      if (s_axi_aresetn = '0') then
598	        o_reg_wdata                  <= (others => (others => '0'));
599	        o_reg_wdata(rst_val_g'range) <= rst_val_g;
600	      else
601	        for reg_byte_index in 0 to 3 loop
602	          if ((axi_waddr_sel = '0') and (axi_wready = '1') and (s_axi_wstrb(reg_byte_index) = '1')) then
603	            o_reg_wdata(to_integer(unsigned(axi_awaddr(REG_ADDR_INDEX_HIGH downto REG_ADDR_INDEX_LOW))))(reg_byte_index * 8 + 7 downto reg_byte_index * 8) <= s_axi_wdata(reg_byte_index * 8 + 7 downto reg_byte_index * 8);
604	          end if;
605	        end loop;
606	      end if;
607	    end if;
608	  end process slv_reg_wr_proc;
609	
610	  -----------------------------------------------------------------------------
611	  -- Memory read/write
612	  -----------------------------------------------------------------------------
613	  mem_rvalid <= '1' when ((axi_raddr_sel = '1') and (axi_fsm = axi_fsm_rd_data) and (axi_rready = '1') and (rpl_rready = '1')) else '0';
614	  g_mem : if use_mem_g generate
615	    o_mem_addr  <= std_logic_vector(axi_awaddr - MEM_ADDR_START) when (axi_waddr_sel = '1') else std_logic_vector(axi_araddr - MEM_ADDR_START);
616	    o_mem_wr(0) <= '1' when ((axi_waddr_sel = '1') and (axi_fsm = axi_fsm_wr_data) and (s_axi_wvalid = '1') and (s_axi_wstrb(0) = '1')) else '0';
617	    o_mem_wr(1) <= '1' when ((axi_waddr_sel = '1') and (axi_fsm = axi_fsm_wr_data) and (s_axi_wvalid = '1') and (s_axi_wstrb(1) = '1')) else '0';
618	    o_mem_wr(2) <= '1' when ((axi_waddr_sel = '1') and (axi_fsm = axi_fsm_wr_data) and (s_axi_wvalid = '1') and (s_axi_wstrb(2) = '1')) else '0';
619	    o_mem_wr(3) <= '1' when ((axi_waddr_sel = '1') and (axi_fsm = axi_fsm_wr_data) and (s_axi_wvalid = '1') and (s_axi_wstrb(3) = '1')) else '0';
620	    o_mem_wdata <= s_axi_wdata;
621	  end generate;
622	  g_nmem : if not use_mem_g generate
623	    o_mem_wr    <= (others => '0');
624	    o_mem_wdata <= (others => '0');
625	    o_mem_addr  <= (others => '0');
626	  end generate;
627	
628	  -----------------------------------------------------------------------------
629	  -- R-Channel Pipeline Stage
630	  -----------------------------------------------------------------------------
631	  -- The logic (ported legacy code) does only assert RVALID after RREADY is present. This violates the AXI specification.
632	  -- By using a pipeline stage to decouple the logic from the bus, this problem can be solved (the PL stage always asserts READY).
633	  b_rplstage : block
634	    signal pl_in_data  : std_logic_vector(34 + axi_id_width_g downto 0);
635	    signal pl_out_data : std_logic_vector(pl_in_data'range);
636	  begin
637	    pl_in_data(31 downto 0)                   <= rpl_rdata;
638	    pl_in_data(33 downto 32)                  <= rpl_rresp;
639	    pl_in_data(34)                            <= rpl_rlast;
640	    pl_in_data(axi_id_width_g + 34 downto 35) <= rpl_rid;
641	
642	    i_rplstage : entity work.psi_common_pl_stage
643	      generic map( width_g  => 35 + axi_id_width_g,
644	                  use_rdy_g => true,
645	                  rst_pol_g => '0')
646	      port map(   clk_i     => s_axi_aclk,
647	                  rst_i     => s_axi_aresetn,
648	                  vld_i     => rpl_rvalid,
649	                  rdy_o     => rpl_rready,
650	                  dat_i     => pl_in_data,
651	                  vld_o     => s_axi_rvalid,
652	                  rdy_i     => s_axi_rready,
653	                  dat_o     => pl_out_data);
654	
655	    s_axi_rdata <= pl_out_data(31 downto 0);
656	    s_axi_rresp <= pl_out_data(33 downto 32);
657	    s_axi_rlast <= pl_out_data(34);
658	    s_axi_rid   <= pl_out_data(axi_id_width_g + 34 downto 35);
659	  end block;
660	
661	end architecture;
662

file.content:
------------------------------------------------------------------------------
--  Copyright (c) 2019 by Paul Scherrer Institute, Switzerland
--  All rights reserved.
--  Authors: Goran Marinkovic, Oliver Bruendler
------------------------------------------------------------------------------

------------------------------------------------------------------------------
-- Description
------------------------------------------------------------------------------
-- This entity implements a full AXI-4 slave for simple IP-Core interfaces. It
-- supports the implementation of registers as well as access to memories.
-- Its only main limitations are, that data for memory accesses must be available for
-- reading after one clock cycle. So except using a synchronous RAM, no additional
-- pipelining is possible and that it only supports 32-bit wide AXI bus.

library ieee;
use ieee.std_logic_1164.all;
use ieee.numeric_std.all;

use work.psi_common_array_pkg.all;
use work.psi_common_math_pkg.all;
use work.psi_common_logic_pkg.all;
--@fomratter:off
entity psi_common_axi_slave_ipif is
  generic(
    -- IP Interface Config
    num_reg_g        : integer  := 32;                      -- Number of registers to implement
    rst_val_g        : t_aslv32 := (0 => (others => '0'));  -- Reset values for registers. The size of the array passed does not have to match NumReg_g, if it does not, the reset values are applied to the first N registers and the other registers are reset to zero.
    use_mem_g        : boolean  := true;                    -- **True** = use memory interface, **False** = use registers only
    -- AXI Config
    axi_id_width_g   : integer  := 1;                       -- Number of bits used for the AXI ID signals
    axi_addr_width_g : integer  := 8                        -- Number of AXI address bits supported
  );
  port(
    -- System
    s_axi_aclk    : in  std_logic;                                        -- system clock
    s_axi_aresetn : in  std_logic;                                        -- system reset active low
    -- Read address channel
    s_axi_arid    : in  std_logic_vector(axi_id_width_g - 1 downto 0);
    s_axi_araddr  : in  std_logic_vector(axi_addr_width_g - 1 downto 0);
    s_axi_arlen   : in  std_logic_vector(7 downto 0);
    s_axi_arsize  : in  std_logic_vector(2 downto 0);
    s_axi_arburst : in  std_logic_vector(1 downto 0);
    s_axi_arlock  : in  std_logic;
    s_axi_arcache : in  std_logic_vector(3 downto 0);
    s_axi_arprot  : in  std_logic_vector(2 downto 0);
    s_axi_arvalid : in  std_logic;
    s_axi_arready : out std_logic;
    -- Read data channel
    s_axi_rid     : out std_logic_vector(axi_id_width_g - 1 downto 0);
    s_axi_rdata   : out std_logic_vector(31 downto 0);
    s_axi_rresp   : out std_logic_vector(1 downto 0);
    s_axi_rlast   : out std_logic;
    s_axi_rvalid  : out std_logic;
    s_axi_rready  : in  std_logic;
    -- Write address channel
    s_axi_awid    : in  std_logic_vector(axi_id_width_g - 1 downto 0);
    s_axi_awaddr  : in  std_logic_vector(axi_addr_width_g - 1 downto 0);
    s_axi_awlen   : in  std_logic_vector(7 downto 0);
    s_axi_awsize  : in  std_logic_vector(2 downto 0);
    s_axi_awburst : in  std_logic_vector(1 downto 0);
    s_axi_awlock  : in  std_logic;
    s_axi_awcache : in  std_logic_vector(3 downto 0);
    s_axi_awprot  : in  std_logic_vector(2 downto 0);
    s_axi_awvalid : in  std_logic;
    s_axi_awready : out std_logic;
    -- Write data channel
    s_axi_wdata   : in  std_logic_vector(31 downto 0);
    s_axi_wstrb   : in  std_logic_vector(3 downto 0);
    s_axi_wlast   : in  std_logic;
    s_axi_wvalid  : in  std_logic;
    s_axi_wready  : out std_logic;
    -- Write response channel
    s_axi_bid     : out std_logic_vector(axi_id_width_g - 1 downto 0);
    s_axi_bresp   : out std_logic_vector(1 downto 0);
    s_axi_bvalid  : out std_logic;
    s_axi_bready  : in  std_logic;
    -- Register Interface
    o_reg_rd      : out std_logic_vector(num_reg_g - 1 downto 0);                     -- Read-pulse for each register
    i_reg_rdata   : in  t_aslv32(0 to num_reg_g - 1)  := (others => (others => '0')); -- Register read values
    o_reg_wr      : out std_logic_vector(num_reg_g - 1 downto 0);                     -- Write-pulse for each register
    o_reg_wdata   : out t_aslv32(0 to num_reg_g - 1);                                 -- Register write values
    -- Memory Interface
    o_mem_addr    : out std_logic_vector(axi_addr_width_g - 1 downto 0);  -- Memory address
    o_mem_wr      : out std_logic_vector(3 downto 0);                     -- Memory byte write enables (one signal per byte)
    o_mem_wdata   : out std_logic_vector(31 downto 0);                    -- Memory write data
    i_mem_rdata   : in  std_logic_vector(31 downto 0) := (others => '0')  -- Memory read data must be valid one clock cycle after o_mem_addr

  );
end entity;
--@fomratter:on
architecture behav of psi_common_axi_slave_ipif is
  -----------------------------------------------------------------------------
  -- AXI slave bus interface
  -----------------------------------------------------------------------------
  type axi_fsm_type is (
    axi_fsm_idle,
    axi_fsm_rd_data,
    axi_fsm_wr_data,
    axi_fsm_wr_resp_delay,
    axi_fsm_wr_done);
  signal axi_fsm_comb          : axi_fsm_type;
  signal axi_fsm               : axi_fsm_type;
  -- ADDR_INDEX_LOW is used for addressing 32/64 bit registers/memories
  -- ADDR_INDEX_LOW = 2 for 32 bits (n downto 2)
  -- ADDR_INDEX_LOW = 3 for 64 bits (n downto 3)
  constant REG_ADDR_INDEX_LOW  : integer                                       := 2;
  constant REG_ADDR_WIDTH      : integer                                       := integer(log2ceil(num_reg_g)) + REG_ADDR_INDEX_LOW;
  constant REG_ADDR_INDEX_HIGH : integer                                       := REG_ADDR_WIDTH - 1;
  constant MEM_ADDR_START      : unsigned(axi_addr_width_g - 1 downto 0)       := to_unsigned(2**(REG_ADDR_WIDTH), axi_addr_width_g);
  constant RESP_OKAY_c         : std_logic_vector(1 downto 0)                  := "00";
  constant RESP_EXOKAY_c       : std_logic_vector(1 downto 0)                  := "01";
  constant RESP_SLVERR_c       : std_logic_vector(1 downto 0)                  := "10";
  constant RESP_DECERR_c       : std_logic_vector(1 downto 0)                  := "11";
  -- Read address channel
  signal axi_arid              : std_logic_vector(axi_id_width_g - 1 downto 0) := (others => '0');
  signal axi_araddr            : unsigned(axi_addr_width_g - 1 downto 0)       := (others => '0');
  signal axi_araddr_last       : unsigned(axi_addr_width_g - 1 downto 0)       := (others => '0');
  signal axi_arlen             : unsigned(7 downto 0)                          := (others => '0');
  signal axi_arsize            : unsigned(axi_addr_width_g - 1 downto 0)       := (others => '0');
  signal axi_arburst           : std_logic_vector(1 downto 0)                  := (others => '0');
  signal axi_arwrap_en         : std_logic                                     := '0';
  signal axi_arwrap            : unsigned(axi_addr_width_g - 1 downto 0)       := (others => '0');
  -- Read data channel
  signal axi_rresp             : std_logic_vector(1 downto 0);
  signal axi_rlast             : std_logic                                     := '0';
  signal axi_rready            : std_logic                                     := '0';
  signal axi_rvalid            : std_logic                                     := '0';
  -- Write address channel
  signal axi_awid              : std_logic_vector(axi_id_width_g - 1 downto 0) := (others => '0');
  signal axi_awaddr            : unsigned(axi_addr_width_g - 1 downto 0)       := (others => '0');
  signal axi_awlen             : unsigned(7 downto 0)                          := (others => '0');
  signal axi_awsize            : unsigned(axi_addr_width_g - 1 downto 0)       := (others => '0');
  signal axi_awburst           : std_logic_vector(1 downto 0)                  := (others => '0');
  signal axi_awwrap_en         : std_logic                                     := '0';
  signal axi_awwrap            : unsigned(axi_addr_width_g - 1 downto 0)       := (others => '0');
  -- Write data channel
  signal axi_wlast             : std_logic                                     := '0';
  signal axi_wready            : std_logic                                     := '0';
  -- Write response channel
  signal axi_bresp             : std_logic_vector(1 downto 0);
  -- Derived signals
  signal axi_raddr_sel         : std_logic                                     := '0';
  signal axi_waddr_sel         : std_logic                                     := '0';
  signal reg_rd                : std_logic_vector(num_reg_g - 1 downto 0)      := (others => '0');
  signal reg_wr                : std_logic_vector(num_reg_g - 1 downto 0)      := (others => '0');
  signal reg_rdata             : std_logic_vector(31 downto 0)                 := (others => '0');
  signal reg_rvalid            : std_logic                                     := '0';
  signal mem_rvalid            : std_logic                                     := '0';
  -- R-channel pipeline stage
  signal rpl_rready            : std_logic;
  signal rpl_rvalid            : std_logic;
  signal rpl_rid               : std_logic_vector(axi_id_width_g - 1 downto 0);
  signal rpl_rdata             : std_logic_vector(31 downto 0);
  signal rpl_rresp             : std_logic_vector(1 downto 0);
  signal rpl_rlast             : std_logic;

begin

  -----------------------------------------------------------------------------
  -- Assertions
  -----------------------------------------------------------------------------
  assert isLog2(num_reg_g) report "###ERROR###: psi_common_axi_slave_ipif: num_reg_g must be a power of two!" severity error;
  assert not (not use_mem_g and num_reg_g = 0) report "###ERROR###: psi_common_axi_slave_ipif: num_reg_g must be > 0 if use_mem_g = true" severity error;

  -----------------------------------------------------------------------------
  -- AXI fsm
  -----------------------------------------------------------------------------
  axi_fsm_comb_proc : process(axi_fsm, axi_rlast, axi_wlast, s_axi_aresetn, s_axi_arvalid, s_axi_awvalid, s_axi_bready, rpl_rready, s_axi_wvalid)
  begin
    if (s_axi_aresetn = '0') then
      axi_fsm_comb <= axi_fsm_idle;
    else
      axi_fsm_comb <= axi_fsm;
      case axi_fsm is
        when axi_fsm_idle =>
          if (s_axi_arvalid = '1') then
            axi_fsm_comb <= axi_fsm_rd_data;
          elsif (s_axi_awvalid = '1') then
            axi_fsm_comb <= axi_fsm_wr_data;
          end if;
        when axi_fsm_rd_data =>
          if ((axi_rlast = '1') and (rpl_rready = '1')) then
            axi_fsm_comb <= axi_fsm_idle;
          end if;
        when axi_fsm_wr_data =>
          if ((axi_wlast = '1') and (s_axi_wvalid = '1')) then
            axi_fsm_comb <= axi_fsm_wr_resp_delay;
          end if;
        when axi_fsm_wr_resp_delay =>
          axi_fsm_comb <= axi_fsm_wr_done;
        when axi_fsm_wr_done =>
          if (s_axi_bready = '1') then
            axi_fsm_comb <= axi_fsm_idle;
          end if;
        when others =>
          axi_fsm_comb <= axi_fsm_idle;
      end case;
    end if;
  end process;

  axi_fsm_proc : process(s_axi_aclk)
  begin
    if rising_edge(s_axi_aclk) then
      axi_fsm <= axi_fsm_comb;
    end if;
  end process axi_fsm_proc;

  -----------------------------------------------------------------------------
  -- AXI ARADDR
  -----------------------------------------------------------------------------
  axi_arwrap_en <= '1' when ((axi_araddr and axi_arwrap) = axi_arwrap) else '0';

  axi_araddr_proc : process(s_axi_aclk)
  begin
    if rising_edge(s_axi_aclk) then
      case axi_fsm is
        when axi_fsm_idle =>
          axi_rresp <= RESP_OKAY_c;
          if (axi_fsm_comb = axi_fsm_rd_data) then
            axi_araddr      <= unsigned(s_axi_araddr);
            axi_araddr_last <= unsigned(s_axi_araddr);
            case (s_axi_arsize) is
              when "000" =>
                axi_arsize <= to_unsigned(1, axi_addr_width_g);
              when "001" =>
                axi_arsize <= to_unsigned(2, axi_addr_width_g);
              when "010" =>
                axi_arsize <= to_unsigned(4, axi_addr_width_g);
              when others =>
                axi_arsize <= to_unsigned(1, axi_addr_width_g);
            end case;
            axi_arburst     <= s_axi_arburst;
            axi_arlen       <= unsigned(s_axi_arlen);
            if (s_axi_arburst = "10") then -- If wrapping burst
              case (s_axi_arlen) is
                when X"01" =>
                  case (s_axi_arsize) is
                    when "000" =>
                      axi_arwrap <= to_unsigned(2 * 1 - 1, axi_addr_width_g);
                    when "001" =>
                      axi_arwrap <= to_unsigned(2 * 2 - 1, axi_addr_width_g);
                    when "010" =>
                      axi_arwrap <= to_unsigned(2 * 4 - 1, axi_addr_width_g);
                    when others =>
                      axi_arwrap <= to_unsigned(2 * 1 - 1, axi_addr_width_g);
                  end case;
                when X"03" =>
                  case (s_axi_arsize) is
                    when "000" =>
                      axi_arwrap <= to_unsigned(4 * 1 - 1, axi_addr_width_g);
                    when "001" =>
                      axi_arwrap <= to_unsigned(4 * 2 - 1, axi_addr_width_g);
                    when "010" =>
                      axi_arwrap <= to_unsigned(4 * 4 - 1, axi_addr_width_g);
                    when others =>
                      axi_arwrap <= to_unsigned(4 * 1 - 1, axi_addr_width_g);
                  end case;
                when X"07" =>
                  case (s_axi_arsize) is
                    when "000" =>
                      axi_arwrap <= to_unsigned(8 * 1 - 1, axi_addr_width_g);
                    when "001" =>
                      axi_arwrap <= to_unsigned(8 * 2 - 1, axi_addr_width_g);
                    when "010" =>
                      axi_arwrap <= to_unsigned(8 * 4 - 1, axi_addr_width_g);
                    when others =>
                      axi_arwrap <= to_unsigned(8 * 1 - 1, axi_addr_width_g);
                  end case;
                when X"0F" =>
                  case (s_axi_arsize) is
                    when "000" =>
                      axi_arwrap <= to_unsigned(16 * 1 - 1, axi_addr_width_g);
                    when "001" =>
                      axi_arwrap <= to_unsigned(16 * 2 - 1, axi_addr_width_g);
                    when "010" =>
                      axi_arwrap <= to_unsigned(16 * 4 - 1, axi_addr_width_g);
                    when others =>
                      axi_arwrap <= to_unsigned(16 * 1 - 1, axi_addr_width_g);
                  end case;
                when others =>
                  axi_arwrap <= to_unsigned(2 * 1 - 1, axi_addr_width_g);
              end case;
            end if;
          end if;
        when axi_fsm_rd_data =>
          -- Produce decoding error if memory is accessed but not enabled
          if unsigned(axi_araddr) >= (num_reg_g * 4) and not use_mem_g then
            axi_rresp <= RESP_DECERR_c;
          end if;
          -- Do access
          if (rpl_rready = '1') then
            case (axi_arburst) is
              when "00" =>              -- Fixed burst
                null;
              when "01" =>              -- Incremental burst
                axi_araddr <= axi_araddr + axi_arsize;
              when "10" =>              -- Wrapping burst
                if (axi_arwrap_en = '1') then
                  axi_araddr <= axi_araddr - axi_arwrap;
                else
                  axi_araddr <= axi_araddr + axi_arsize;
                end if;
              when others =>            -- Reserved
                null;
            end case;
            axi_araddr_last <= axi_araddr;
          else
            axi_araddr <= axi_araddr_last;
          end if;
          if (axi_rvalid = '1') then
            axi_arlen <= axi_arlen - 1;
          end if;
        when others =>
          null;
      end case;
    end if;
  end process axi_araddr_proc;

  -----------------------------------------------------------------------------
  -- AXI RADDR denotes register or memory
  -----------------------------------------------------------------------------
  axi_raddr_sel <= '1' when ((axi_fsm = axi_fsm_rd_data) and (to_integer(unsigned(axi_araddr_last(axi_addr_width_g - 1 downto REG_ADDR_WIDTH))) /= 0)) else '0';

  -----------------------------------------------------------------------------
  -- AXI ARREADY
  -----------------------------------------------------------------------------
  s_axi_arready <= '1' when ((axi_fsm = axi_fsm_idle) and (axi_fsm_comb = axi_fsm_rd_data)) else '0';

  -----------------------------------------------------------------------------
  -- AXI RID
  -----------------------------------------------------------------------------
  axi_rid_proc : process(s_axi_aclk)
  begin
    if rising_edge(s_axi_aclk) then
      if (axi_fsm = axi_fsm_idle) then
        if (axi_fsm_comb = axi_fsm_rd_data) then
          axi_arid <= s_axi_arid;
        else
          axi_arid <= (others => '0');
        end if;
      end if;
    end if;
  end process axi_rid_proc;

  rpl_rid <= axi_arid;

  -----------------------------------------------------------------------------
  -- AXI RREADY
  -----------------------------------------------------------------------------
  axi_rready_proc : process(s_axi_aclk)
  begin
    if rising_edge(s_axi_aclk) then
      if (axi_fsm = axi_fsm_rd_data) then
        axi_rready <= rpl_rready;
      else
        axi_rready <= '0';
      end if;
    end if;
  end process axi_rready_proc;

  -----------------------------------------------------------------------------
  -- AXI RVALID
  -----------------------------------------------------------------------------
  axi_rvalid <= reg_rvalid or mem_rvalid;
  rpl_rvalid <= axi_rvalid;

  -----------------------------------------------------------------------------
  -- AXI RLAST
  -----------------------------------------------------------------------------
  axi_rlast <= '1' when (((mem_rvalid = '1') or (reg_rvalid = '1')) and (axi_arlen = X"00")) else '0';
  rpl_rlast <= axi_rlast;

  -----------------------------------------------------------------------------
  -- AXI RRESP
  -----------------------------------------------------------------------------
  rpl_rresp <= axi_rresp;

  -----------------------------------------------------------------------------
  -- AXI AWADDR
  -----------------------------------------------------------------------------
  axi_awwrap_en <= '1' when ((axi_awaddr and axi_awwrap) = axi_awwrap) else '0';

  axi_awaddr_proc : process(s_axi_aclk)
  begin
    if rising_edge(s_axi_aclk) then
      case axi_fsm is
        when axi_fsm_idle =>
          axi_bresp <= RESP_OKAY_c;
          if (axi_fsm_comb = axi_fsm_wr_data) then
            axi_awaddr  <= unsigned(s_axi_awaddr);
            case (s_axi_awsize) is
              when "000" =>
                axi_awsize <= to_unsigned(1, axi_addr_width_g);
              when "001" =>
                axi_awsize <= to_unsigned(2, axi_addr_width_g);
              when "010" =>
                axi_awsize <= to_unsigned(4, axi_addr_width_g);
              when others =>
                axi_awsize <= to_unsigned(1, axi_addr_width_g);
            end case;
            axi_awburst <= s_axi_awburst;
            axi_awlen   <= unsigned(s_axi_awlen);
            if (s_axi_awburst = "10") then -- If wrapping burst
              case (s_axi_awlen) is
                when X"01" =>
                  case (s_axi_awsize) is
                    when "000" =>
                      axi_awwrap <= to_unsigned(2 * 1 - 1, axi_addr_width_g);
                    when "001" =>
                      axi_awwrap <= to_unsigned(2 * 2 - 1, axi_addr_width_g);
                    when "010" =>
                      axi_awwrap <= to_unsigned(2 * 4 - 1, axi_addr_width_g);
                    when others =>
                      axi_awwrap <= to_unsigned(2 * 1 - 1, axi_addr_width_g);
                  end case;
                when X"03" =>
                  case (s_axi_awsize) is
                    when "000" =>
                      axi_awwrap <= to_unsigned(4 * 1 - 1, axi_addr_width_g);
                    when "001" =>
                      axi_awwrap <= to_unsigned(4 * 2 - 1, axi_addr_width_g);
                    when "010" =>
                      axi_awwrap <= to_unsigned(4 * 4 - 1, axi_addr_width_g);
                    when others =>
                      axi_awwrap <= to_unsigned(4 * 1 - 1, axi_addr_width_g);
                  end case;
                when X"07" =>
                  case (s_axi_awsize) is
                    when "000" =>
                      axi_awwrap <= to_unsigned(8 * 1 - 1, axi_addr_width_g);
                    when "001" =>
                      axi_awwrap <= to_unsigned(8 * 2 - 1, axi_addr_width_g);
                    when "010" =>
                      axi_awwrap <= to_unsigned(8 * 4 - 1, axi_addr_width_g);
                    when others =>
                      axi_awwrap <= to_unsigned(8 * 1 - 1, axi_addr_width_g);
                  end case;
                when X"0F" =>
                  case (s_axi_awsize) is
                    when "000" =>
                      axi_awwrap <= to_unsigned(16 * 1 - 1, axi_addr_width_g);
                    when "001" =>
                      axi_awwrap <= to_unsigned(16 * 2 - 1, axi_addr_width_g);
                    when "010" =>
                      axi_awwrap <= to_unsigned(16 * 4 - 1, axi_addr_width_g);
                    when others =>
                      axi_awwrap <= to_unsigned(16 * 1 - 1, axi_addr_width_g);
                  end case;
                when others =>
                  axi_awwrap <= to_unsigned(2 * 1 - 1, axi_addr_width_g);
              end case;
            end if;
          end if;
        when axi_fsm_wr_data =>
          -- Produce decoding error if memory is accessed but not enabled
          if unsigned(axi_awaddr) >= (num_reg_g * 4) and not use_mem_g then
            axi_bresp <= RESP_DECERR_c;
          end if;
          -- Do access
          if (s_axi_wvalid = '1') then
            case (axi_awburst) is
              when "00" =>              -- Fixed burst
                null;
              when "01" =>              -- Incremental burst
                axi_awaddr <= axi_awaddr + axi_awsize;
              when "10" =>              -- Wrapping burst
                if (axi_awwrap_en = '1') then
                  axi_awaddr <= axi_awaddr - axi_awwrap;
                else
                  axi_awaddr <= axi_awaddr + axi_awsize;
                end if;
              when others =>            -- Reserved
                null;
            end case;
          end if;
          if (axi_wready = '1') then
            axi_awlen <= axi_awlen - 1;
          end if;
        when others =>
          null;
      end case;
    end if;
  end process axi_awaddr_proc;

  -----------------------------------------------------------------------------
  -- AXI WADDR denotes register or memory
  -----------------------------------------------------------------------------
  axi_waddr_sel <= '1' when ((axi_fsm = axi_fsm_wr_data) and (to_integer(unsigned(axi_awaddr(axi_addr_width_g - 1 downto REG_ADDR_WIDTH))) /= 0)) else '0';

  -----------------------------------------------------------------------------
  -- AXI AWREADY
  -----------------------------------------------------------------------------
  s_axi_awready <= '1' when ((axi_fsm = axi_fsm_idle) and (axi_fsm_comb = axi_fsm_wr_data)) else '0';

  -----------------------------------------------------------------------------
  -- AXI WID
  -----------------------------------------------------------------------------
  axi_wid_proc : process(s_axi_aclk)
  begin
    if rising_edge(s_axi_aclk) then
      if (axi_fsm = axi_fsm_idle) then
        if (axi_fsm_comb = axi_fsm_wr_data) then
          axi_awid <= s_axi_awid;
        else
          axi_awid <= (others => '0');
        end if;
      end if;
    end if;
  end process axi_wid_proc;

  s_axi_bid <= axi_awid;

  -----------------------------------------------------------------------------
  -- AXI WREADY
  -----------------------------------------------------------------------------
  axi_wready   <= '1' when ((axi_fsm = axi_fsm_wr_data) and (s_axi_wvalid = '1')) else '0';
  s_axi_wready <= axi_wready;

  -----------------------------------------------------------------------------
  -- AXI WLAST
  -----------------------------------------------------------------------------
  axi_wlast <= '1' when ((axi_wready = '1') and (axi_awlen = X"00")) else '0';

  -----------------------------------------------------------------------------
  -- AXI BRESP
  -----------------------------------------------------------------------------
  s_axi_bresp <= axi_bresp;

  -----------------------------------------------------------------------------
  -- AXI BVALID
  -----------------------------------------------------------------------------
  s_axi_bvalid <= '1' when (axi_fsm = axi_fsm_wr_done) else '0';

  ---------------------------------------------------------------------------
  -- IP to Bus data
  ---------------------------------------------------------------------------
  rpl_rdata <= reg_rdata when (reg_rvalid = '1')
               else i_mem_rdata when (mem_rvalid = '1' and use_mem_g)
               else (others => '0');

  ---------------------------------------------------------------------------
  -- Register read
  ---------------------------------------------------------------------------
  reg_rvalid <= '1' when ((axi_raddr_sel = '0') and (axi_fsm = axi_fsm_rd_data) and (axi_rready = '1') and (rpl_rready = '1')) else '0';

  b_rdreg : block
    signal rd_data_ext : t_aslv32(0 to num_reg_g + 1) := (others => (others => '0'));
  begin
    rd_data_ext(0 to i_reg_rdata'high) <= i_reg_rdata; -- extend number of registers to prevent indexing errors
    reg_rdata_proc : process(s_axi_aclk) is
    begin
      if rising_edge(s_axi_aclk) then
        reg_rdata(31 downto 0) <= rd_data_ext(to_integer(unsigned(axi_araddr(REG_ADDR_INDEX_HIGH downto REG_ADDR_INDEX_LOW))));
      end if;
    end process reg_rdata_proc;
  end block;

  reg_rd_proc : process(s_axi_aclk) is
  begin
    if rising_edge(s_axi_aclk) then
      if (s_axi_aresetn = '0') then
        reg_rd <= (others => '0');
      else
        reg_rd <= (others => '0');
        if (reg_rvalid = '1') then
          reg_rd(to_integer(unsigned(axi_araddr_last(REG_ADDR_INDEX_HIGH downto REG_ADDR_INDEX_LOW)))) <= '1';
        end if;
      end if;
    end if;
  end process reg_rd_proc;

  o_reg_rd <= reg_rd;

  ---------------------------------------------------------------------------
  -- Register write
  ---------------------------------------------------------------------------
  reg_wr_proc : process(s_axi_aclk) is
  begin
    if rising_edge(s_axi_aclk) then
      if (s_axi_aresetn = '0') then
        reg_wr <= (others => '0');
      else
        reg_wr <= (others => '0');
        if ((axi_waddr_sel = '0') and (axi_wready = '1')) then
          reg_wr(to_integer(unsigned(axi_awaddr(REG_ADDR_INDEX_HIGH downto REG_ADDR_INDEX_LOW)))) <= '1';
        end if;
      end if;
    end if;
  end process reg_wr_proc;

  o_reg_wr <= reg_wr;

  slv_reg_wr_proc : process(s_axi_aclk) is
  begin
    if rising_edge(s_axi_aclk) then
      if (s_axi_aresetn = '0') then
        o_reg_wdata                  <= (others => (others => '0'));
        o_reg_wdata(rst_val_g'range) <= rst_val_g;
      else
        for reg_byte_index in 0 to 3 loop
          if ((axi_waddr_sel = '0') and (axi_wready = '1') and (s_axi_wstrb(reg_byte_index) = '1')) then
            o_reg_wdata(to_integer(unsigned(axi_awaddr(REG_ADDR_INDEX_HIGH downto REG_ADDR_INDEX_LOW))))(reg_byte_index * 8 + 7 downto reg_byte_index * 8) <= s_axi_wdata(reg_byte_index * 8 + 7 downto reg_byte_index * 8);
          end if;
        end loop;
      end if;
    end if;
  end process slv_reg_wr_proc;

  -----------------------------------------------------------------------------
  -- Memory read/write
  -----------------------------------------------------------------------------
  mem_rvalid <= '1' when ((axi_raddr_sel = '1') and (axi_fsm = axi_fsm_rd_data) and (axi_rready = '1') and (rpl_rready = '1')) else '0';
  g_mem : if use_mem_g generate
    o_mem_addr  <= std_logic_vector(axi_awaddr - MEM_ADDR_START) when (axi_waddr_sel = '1') else std_logic_vector(axi_araddr - MEM_ADDR_START);
    o_mem_wr(0) <= '1' when ((axi_waddr_sel = '1') and (axi_fsm = axi_fsm_wr_data) and (s_axi_wvalid = '1') and (s_axi_wstrb(0) = '1')) else '0';
    o_mem_wr(1) <= '1' when ((axi_waddr_sel = '1') and (axi_fsm = axi_fsm_wr_data) and (s_axi_wvalid = '1') and (s_axi_wstrb(1) = '1')) else '0';
    o_mem_wr(2) <= '1' when ((axi_waddr_sel = '1') and (axi_fsm = axi_fsm_wr_data) and (s_axi_wvalid = '1') and (s_axi_wstrb(2) = '1')) else '0';
    o_mem_wr(3) <= '1' when ((axi_waddr_sel = '1') and (axi_fsm = axi_fsm_wr_data) and (s_axi_wvalid = '1') and (s_axi_wstrb(3) = '1')) else '0';
    o_mem_wdata <= s_axi_wdata;
  end generate;
  g_nmem : if not use_mem_g generate
    o_mem_wr    <= (others => '0');
    o_mem_wdata <= (others => '0');
    o_mem_addr  <= (others => '0');
  end generate;

  -----------------------------------------------------------------------------
  -- R-Channel Pipeline Stage
  -----------------------------------------------------------------------------
  -- The logic (ported legacy code) does only assert RVALID after RREADY is present. This violates the AXI specification.
  -- By using a pipeline stage to decouple the logic from the bus, this problem can be solved (the PL stage always asserts READY).
  b_rplstage : block
    signal pl_in_data  : std_logic_vector(34 + axi_id_width_g downto 0);
    signal pl_out_data : std_logic_vector(pl_in_data'range);
  begin
    pl_in_data(31 downto 0)                   <= rpl_rdata;
    pl_in_data(33 downto 32)                  <= rpl_rresp;
    pl_in_data(34)                            <= rpl_rlast;
    pl_in_data(axi_id_width_g + 34 downto 35) <= rpl_rid;

    i_rplstage : entity work.psi_common_pl_stage
      generic map( width_g  => 35 + axi_id_width_g,
                  use_rdy_g => true,
                  rst_pol_g => '0')
      port map(   clk_i     => s_axi_aclk,
                  rst_i     => s_axi_aresetn,
                  vld_i     => rpl_rvalid,
                  rdy_o     => rpl_rready,
                  dat_i     => pl_in_data,
                  vld_o     => s_axi_rvalid,
                  rdy_i     => s_axi_rready,
                  dat_o     => pl_out_data);

    s_axi_rdata <= pl_out_data(31 downto 0);
    s_axi_rresp <= pl_out_data(33 downto 32);
    s_axi_rlast <= pl_out_data(34);
    s_axi_rid   <= pl_out_data(axi_id_width_g + 34 downto 35);
  end block;

end architecture;

