6	
7	------------------------------------------------------------------------------
8	-- Description
9	------------------------------------------------------------------------------
10	-- AXI helper package to simplify port connections using records.
11	-- Designed for ISE projects with IFC1210.
12	--
13	-- The following Abreviations in signal names are used to identify the direction.
14	-- sm/SM = Slave  -> Master
15	-- ms/MS = Master -> Slave
16	--
17	-- Usage example:
18	--
19	--    port (
20	--        ------- AXI Slave interfaces:
21	--        axi_slv2_o   : out rec_axi_sm   := C_AXI_SM_DEF;
22	--        axi_slv2_i   : in  rec_axi_ms   := C_AXI_MS_DEF;
23	--        ------- AXI Master interfaces:
24	--        axi_mst0_o   : out rec_axi_ms   := C_AXI_MS_DEF;
25	--        axi_mst0_i   : in  rec_axi_sm   := C_AXI_SM_DEF;
26	--    );
27	--
28	
29	library ieee;
30	use ieee.std_logic_1164.all;
31	
32	package psi_common_axi_pkg is
33	
34	    -- AXI BUS parameters:
35	    ---------------------------------------------- 
36	    constant  C_S_AXI_ID_WIDTH            : integer := 1;
37	    constant  C_S_AXI_DATA_WIDTH          : integer := 32;
38	    constant  C_S_AXI_ADDR_WIDTH          : integer := 32;
39	    constant  C_S_AXI_ARUSER_WIDTH        : integer := 1;
40	    constant  C_S_AXI_RUSER_WIDTH         : integer := 1;
41	    constant  C_S_AXI_AWUSER_WIDTH        : integer := 1;
42	    constant  C_S_AXI_WUSER_WIDTH         : integer := 1;
43	    constant  C_S_AXI_BUSER_WIDTH         : integer := 1;
44	    
45	    -- AXI Read Address Channel:
46	    ---------------------------------------------- 
47	    type axi_ms_rd_addr is record
48	      id        : std_logic_vector(C_S_AXI_ID_WIDTH-1   downto 0);
49	      addr      : std_logic_vector(C_S_AXI_ADDR_WIDTH-1 downto 0);
50	      len       : std_logic_vector(7 downto 0);
51	      size      : std_logic_vector(2 downto 0);
52	      burst     : std_logic_vector(1 downto 0);
53	      lock      : std_logic;
54	      cache     : std_logic_vector(3 downto 0);
55	      prot      : std_logic_vector(2 downto 0);
56	      qos       : std_logic_vector(3 downto 0);
57	      region    : std_logic_vector(3 downto 0);
58	      user      : std_logic_vector(C_S_AXI_ARUSER_WIDTH-1 downto 0);
59	      valid     : std_logic;
60	    end record;
61	    
62	    type axi_sm_rd_addr is record
63	      ready     : std_logic;
64	    end record;
65	    
66	    -- AXI Read Data Channel:
67	    ----------------------------------------------
68	    type axi_ms_rd_data is record
69	      ready      :  std_logic;
70	    end record;
71	    
72	    type axi_sm_rd_data is record
73	      id         : std_logic_vector(C_S_AXI_ID_WIDTH-1 downto 0);
74	      data       : std_logic_vector(C_S_AXI_DATA_WIDTH-1 downto 0);
75	      resp       : std_logic_vector(1 downto 0);
76	      last       : std_logic;
77	      user       : std_logic_vector(C_S_AXI_RUSER_WIDTH-1 downto 0);
78	      valid      : std_logic;
79	    end record;
80	    
81	    -- AXI Write Address Channel:
82	    ----------------------------------------------
83	    type axi_ms_wr_addr is record
84	      id      :  std_logic_vector(C_S_AXI_ID_WIDTH-1   downto 0);
85	      addr    :  std_logic_vector(C_S_AXI_ADDR_WIDTH-1 downto 0);
86	      len     :  std_logic_vector(7 downto 0);
87	      size    :  std_logic_vector(2 downto 0);
88	      burst   :  std_logic_vector(1 downto 0);
89	      lock    :  std_logic;
90	      cache   :  std_logic_vector(3 downto 0);
91	      prot    :  std_logic_vector(2 downto 0);
92	      qos     :  std_logic_vector(3 downto 0);
93	      region  :  std_logic_vector(3 downto 0);
94	      user    :  std_logic_vector(C_S_AXI_AWUSER_WIDTH-1 downto 0);
95	      valid   :  std_logic;
96	    end record;
97	    
98	    type axi_sm_wr_addr is record
99	      ready      :  std_logic;
100	    end record;
101	    
102	    -- AXI Write Data Channel:
103	    ----------------------------------------------
104	    type axi_ms_wr_data is record
105	      data      : std_logic_vector( C_S_AXI_DATA_WIDTH-1    downto 0);
106	      strb      : std_logic_vector((C_S_AXI_DATA_WIDTH/8)-1 downto 0);
107	      last      : std_logic;
108	      user      : std_logic_vector(C_S_AXI_WUSER_WIDTH-1 downto 0);
109	      valid     : std_logic;
110	    end record;
111	    
112	    type axi_sm_wr_data is record
113	      ready     : std_logic;
114	    end record;
115	    
116	    -- AXI Write Response Channel:
117	    ----------------------------------------------
118	    type axi_ms_wr_resp is record
119	      ready         : std_logic;
120	    end record;
121	    
122	    type axi_sm_wr_resp is record
123	      id            : std_logic_vector(C_S_AXI_ID_WIDTH-1 downto 0);
124	      resp          : std_logic_vector(1 downto 0);
125	      user          : std_logic_vector(C_S_AXI_BUSER_WIDTH-1 downto 0);
126	      valid         : std_logic;
127	    end record;
128	    
129	    -- AXI Bus:
130	    ----------------------------------------------
131	    type rec_axi_ms is record
132	      ar : axi_ms_rd_addr;
133	      dr : axi_ms_rd_data;
134	      aw : axi_ms_wr_addr;
135	      dw : axi_ms_wr_data;
136	      b  : axi_ms_wr_resp;
137	    end record;
138	    
139	    type rec_axi_sm is record
140	      ar : axi_sm_rd_addr;
141	      dr : axi_sm_rd_data;
142	      aw : axi_sm_wr_addr;
143	      dw : axi_sm_wr_data;
144	      b  : axi_sm_wr_resp;
145	    end record;
146	    
147	    -- AXI Bus Array:
148	    ----------------------------------------------
149	    type typ_arr_axi_sm  is array (natural range <>) of rec_axi_sm;
150	    type typ_arr_axi_ms  is array (natural range <>) of rec_axi_ms;
151	    
152	    
153	    -- AXI Stream Channel
154	    ----------------------------------------------
155	    type axi_strm_src_oup is record
156	        data        : std_logic_vector(31 downto 0);
157	        valid       : std_logic;
158	        last        : std_logic;
159	    end record;
160	    
161	    type axi_strm_src_inp is record
162	        ready       : std_logic;
163	    end record;
164	    
165	    -- Initialization:
166	    ----------------------------------------------
167	    constant C_AXI_MS_DEF : rec_axi_ms := (
168	                ar  => ((others=>'0'),(others=>'0'),(others=>'0'),(others=>'0'),(others=>'0'),'0',(others=>'0'),(others=>'0'),(others=>'0'),(others=>'0'),(others=>'0'),'0'),
169	                dr  => (others=>'0'),
170	                aw  => ((others=>'0'),(others=>'0'),(others=>'0'),(others=>'0'),(others=>'0'),'0',(others=>'0'),(others=>'0'),(others=>'0'),(others=>'0'),(others=>'0'),'0'),
171	                dw  => ((others=>'0'),(others=>'0'),'0',(others=>'0'),'0'),
172	                b   => (others=>'0')
173	                );
174	                
175	    constant C_AXI_SM_DEF : rec_axi_sm := (
