6	
7	------------------------------------------------------------------------------
8	-- Description
9	------------------------------------------------------------------------------
10	-- This entity implements a full AXI-4 slave for simple IP-Core interfaces. It
11	-- supports the implementation of registers as well as access to memories.
12	-- Its only main limitations are, that data for memory accesses must be available for
13	-- reading after one clock cycle. So except using a synchronous RAM, no additional
14	-- pipelining is possible and that it only supports 64-bit wide AXI bus.
15	------------------------------------------------------------------------------
16	
17	library ieee;
18	use ieee.std_logic_1164.all;
19	use ieee.numeric_std.all;
20	
21	use work.psi_common_array_pkg.all;
22	use work.psi_common_math_pkg.all;
23	use work.psi_common_logic_pkg.all;
24	
25	entity psi_common_axi_slave_ipif64 is
26	  generic(
27	    -- IP Interface Config
28	    num_reg_g        : integer  := 32;                      -- $$ export=true $$
29	    rst_val_g        : t_aslv64 := (0 => (others => '0'));  -- $$ constant=(X"0001A123B123C123", X"0002123456789ABC") $$
30	    use_mem_g        : boolean  := true;                    -- $$ export=true $$
31	    -- AXI Config
32	    axi_id_width_g   : integer  := 1;
33	    axi_addr_width_g : integer  := 9;
34	    axi_data_width_g : integer  := 64;
35	    axi_byte_width_g : integer  := 64 / 8
36	  );
37	  port(
38	    --------------------------------------------------------------------------
39	    -- AXI Slave Bus Interface
40	    --------------------------------------------------------------------------
41	    -- System
42	    s_axi_aclk    : in  std_logic;                                          -- $$ type=clk; freq=100e6 $$
43	    s_axi_aresetn : in  std_logic;                                          -- $$ type=rst; clk=s_axi_aclk; lowactive=true $$
44	    -- Read address channel
45	    s_axi_arid    : in  std_logic_vector(axi_id_width_g - 1 downto 0);      -- $$ proc=axi $$
46	    s_axi_araddr  : in  std_logic_vector(axi_addr_width_g - 1 downto 0);    -- $$ proc=axi $$
47	    s_axi_arlen   : in  std_logic_vector(7 downto 0);                       -- $$ proc=axi $$
48	    s_axi_arsize  : in  std_logic_vector(2 downto 0);                       -- $$ proc=axi $$
49	    s_axi_arburst : in  std_logic_vector(1 downto 0);                       -- $$ proc=axi $$
50	    s_axi_arlock  : in  std_logic;                                          -- $$ proc=axi $$
51	    s_axi_arcache : in  std_logic_vector(3 downto 0);                       -- $$ proc=axi $$
52	    s_axi_arprot  : in  std_logic_vector(2 downto 0);                       -- $$ proc=axi $$
53	    s_axi_arvalid : in  std_logic;                                          -- $$ proc=axi $$
54	    s_axi_arready : out std_logic;                                          -- $$ proc=axi $$
55	    -- Read data channel
56	    s_axi_rid     : out std_logic_vector(axi_id_width_g - 1 downto 0);      -- $$ proc=axi $$
57	    s_axi_rdata   : out std_logic_vector(axi_data_width_g - 1 downto 0);    -- $$ proc=axi $$
58	    s_axi_rresp   : out std_logic_vector(1 downto 0);                       -- $$ proc=axi $$
59	    s_axi_rlast   : out std_logic;                                          -- $$ proc=axi $$
60	    s_axi_rvalid  : out std_logic;                                          -- $$ proc=axi $$
61	    s_axi_rready  : in  std_logic;                                          -- $$ proc=axi $$
62	    -- Write address channel
63	    s_axi_awid    : in  std_logic_vector(axi_id_width_g - 1 downto 0);      -- $$ proc=axi $$
64	    s_axi_awaddr  : in  std_logic_vector(axi_addr_width_g - 1 downto 0);    -- $$ proc=axi $$
65	    s_axi_awlen   : in  std_logic_vector(7 downto 0);                       -- $$ proc=axi $$
66	    s_axi_awsize  : in  std_logic_vector(2 downto 0);                       -- $$ proc=axi $$
67	    s_axi_awburst : in  std_logic_vector(1 downto 0);                       -- $$ proc=axi $$
68	    s_axi_awlock  : in  std_logic;                                          -- $$ proc=axi $$
69	    s_axi_awcache : in  std_logic_vector(3 downto 0);                       -- $$ proc=axi $$
70	    s_axi_awprot  : in  std_logic_vector(2 downto 0);                       -- $$ proc=axi $$
71	    s_axi_awvalid : in  std_logic;                                          -- $$ proc=axi $$
72	    s_axi_awready : out std_logic;                                          -- $$ proc=axi $$
73	    -- Write data channel
74	    s_axi_wdata   : in  std_logic_vector(axi_data_width_g - 1 downto 0);    -- $$ proc=axi $$
75	    s_axi_wstrb   : in  std_logic_vector(axi_byte_width_g - 1 downto 0);    -- $$ proc=axi $$
76	    s_axi_wlast   : in  std_logic;                                          -- $$ proc=axi $$
77	    s_axi_wvalid  : in  std_logic;                                          -- $$ proc=axi $$
78	    s_axi_wready  : out std_logic;                                          -- $$ proc=axi $$
79	    -- Write response channel
80	    s_axi_bid     : out std_logic_vector(axi_id_width_g - 1 downto 0);      -- $$ proc=axi $$
81	    s_axi_bresp   : out std_logic_vector(1 downto 0);                       -- $$ proc=axi $$
82	    s_axi_bvalid  : out std_logic;                                          -- $$ proc=axi $$
83	    s_axi_bready  : in  std_logic;                                          -- $$ proc=axi $$
84	    -- Register Interface
85	    o_reg_rd      : out std_logic_vector(num_reg_g - 1 downto 0);           -- $$ proc=ip $$
86	    i_reg_rdata   : in  t_aslv64(0 to num_reg_g - 1) := (others => (others => '0')); -- $$ proc=ip $$
87	    o_reg_wr      : out std_logic_vector(num_reg_g - 1 downto 0);           -- $$ proc=ip $$
88	    o_reg_wdata   : out t_aslv64(0 to num_reg_g - 1);                       -- $$ proc=ip $$
89	    -- Memory Interface
90	    o_mem_addr    : out std_logic_vector(axi_addr_width_g - 1 downto 0);    -- $$ proc=ip $$
91	    o_mem_wr      : out std_logic_vector(axi_byte_width_g - 1 downto 0);    -- $$ proc=ip $$
92	    o_mem_wdata   : out std_logic_vector(axi_data_width_g - 1 downto 0);    -- $$ proc=ip $$
93	    i_mem_rdata   : in  std_logic_vector(axi_data_width_g - 1 downto 0) := (others => '0') -- $$ proc=ip $$
94	  );
95	end entity;
96	
97	architecture behav of psi_common_axi_slave_ipif64 is
98	
99	  -----------------------------------------------------------------------------
100	  -- AXI slave bus interface
101	  -----------------------------------------------------------------------------
102	  type axi_fsm_type is (
103	    axi_fsm_idle,
104	    axi_fsm_rd_data,
105	    axi_fsm_wr_data,
106	    axi_fsm_wr_resp_delay,
107	    axi_fsm_wr_done
108	  );
109	  signal axi_fsm_comb          : axi_fsm_type;
110	  signal axi_fsm               : axi_fsm_type;
111	  -- ADDR_INDEX_LOW is used for addressing 32/64 bit registers/memories
112	  -- ADDR_INDEX_LOW = 2 for 32 bits (n downto 2)
113	  -- ADDR_INDEX_LOW = 3 for 64 bits (n downto 3)
114	  constant REG_ADDR_INDEX_LOW  : integer                                         := 3;
115	  constant REG_ADDR_WIDTH      : integer                                         := integer(log2ceil(num_reg_g)) + REG_ADDR_INDEX_LOW;
116	  constant REG_ADDR_INDEX_HIGH : integer                                         := REG_ADDR_WIDTH - 1;
117	  constant MEM_ADDR_START      : unsigned(axi_addr_width_g - 1 downto 0)         := to_unsigned(2**(REG_ADDR_WIDTH), axi_addr_width_g);
118	  constant RESP_OKAY_c         : std_logic_vector(1 downto 0)                    := "00";
119	  constant RESP_EXOKAY_c       : std_logic_vector(1 downto 0)                    := "01";
120	  constant RESP_SLVERR_c       : std_logic_vector(1 downto 0)                    := "10";
121	  constant RESP_DECERR_c       : std_logic_vector(1 downto 0)                    := "11";
122	  -- Read address channel
123	  signal axi_arid              : std_logic_vector(axi_id_width_g - 1 downto 0)   := (others => '0');
124	  signal axi_araddr            : unsigned(axi_addr_width_g - 1 downto 0)         := (others => '0');
125	  signal axi_araddr_last       : unsigned(axi_addr_width_g - 1 downto 0)         := (others => '0');
126	  signal axi_arlen             : unsigned(7 downto 0)                            := (others => '0');
127	  signal axi_arsize            : unsigned(axi_addr_width_g - 1 downto 0)         := (others => '0');
128	  signal axi_arburst           : std_logic_vector(1 downto 0)                    := (others => '0');
129	  signal axi_arwrap_en         : std_logic                                       := '0';
130	  signal axi_arwrap            : unsigned(axi_addr_width_g - 1 downto 0)         := (others => '0');
131	  -- Read data channel
132	  signal axi_rresp             : std_logic_vector(1 downto 0);
133	  signal axi_rlast             : std_logic                                       := '0';
134	  signal axi_rready            : std_logic                                       := '0';
135	  signal axi_rvalid            : std_logic                                       := '0';
136	  -- Write address channel
137	  signal axi_awid              : std_logic_vector(axi_id_width_g - 1 downto 0)   := (others => '0');
138	  signal axi_awaddr            : unsigned(axi_addr_width_g - 1 downto 0)         := (others => '0');
139	  signal axi_awlen             : unsigned(7 downto 0)                            := (others => '0');
140	  signal axi_awsize            : unsigned(axi_addr_width_g - 1 downto 0)         := (others => '0');
141	  signal axi_awburst           : std_logic_vector(1 downto 0)                    := (others => '0');
142	  signal axi_awwrap_en         : std_logic                                       := '0';
143	  signal axi_awwrap            : unsigned(axi_addr_width_g - 1 downto 0)         := (others => '0');
144	  -- Write data channel
145	  signal axi_wlast             : std_logic                                       := '0';
146	  signal axi_wready            : std_logic                                       := '0';
147	  -- Write response channel
148	  signal axi_bresp             : std_logic_vector(1 downto 0);
149	  -- Derived signals
150	  signal axi_raddr_sel         : std_logic                                       := '0';
151	  signal axi_waddr_sel         : std_logic                                       := '0';
152	  signal reg_rd                : std_logic_vector(num_reg_g - 1 downto 0)        := (others => '0');
153	  signal reg_wr                : std_logic_vector(num_reg_g - 1 downto 0)        := (others => '0');
154	  signal reg_rdata             : std_logic_vector(axi_data_width_g - 1 downto 0) := (others => '0');
155	  signal reg_rvalid            : std_logic                                       := '0';
156	  signal mem_rvalid            : std_logic                                       := '0';
157	  -- R-channel pipeline stage
158	  signal rpl_rready            : std_logic;
159	  signal rpl_rvalid            : std_logic;
160	  signal rpl_rid               : std_logic_vector(axi_id_width_g - 1 downto 0);
161	  signal rpl_rdata             : std_logic_vector(axi_data_width_g - 1 downto 0);
162	  signal rpl_rresp             : std_logic_vector(1 downto 0);
163	  signal rpl_rlast             : std_logic;
164	
165	begin
166	  -----------------------------------------------------------------------------
167	  -- Assertions
168	  -----------------------------------------------------------------------------
169	  assert isLog2(num_reg_g) report "###ERROR###: psi_common_axi_slave_ipif64: num_reg_g must be a power of two!" severity error;
170	  assert not (not use_mem_g and num_reg_g = 0) report "###ERROR###: psi_common_axi_slave_ipif64: num_reg_g must be > 0 if use_mem_g = true" severity error;
171	
172	  -----------------------------------------------------------------------------
173	  -- AXI fsm
174	  -----------------------------------------------------------------------------
175	  axi_fsm_comb_proc : process(axi_fsm, axi_rlast, axi_wlast, s_axi_aresetn, s_axi_arvalid, s_axi_awvalid, s_axi_bready, rpl_rready, s_axi_wvalid)
176	  begin
177	    if (s_axi_aresetn = '0') then
178	      axi_fsm_comb <= axi_fsm_idle;
179	    else
180	      axi_fsm_comb <= axi_fsm;
181	      case axi_fsm is
182	        when axi_fsm_idle =>
183	          if (s_axi_arvalid = '1') then
184	            axi_fsm_comb <= axi_fsm_rd_data;
185	          elsif (s_axi_awvalid = '1') then
186	            axi_fsm_comb <= axi_fsm_wr_data;
187	          end if;
188	        when axi_fsm_rd_data =>
189	          if ((axi_rlast = '1') and (rpl_rready = '1')) then
190	            axi_fsm_comb <= axi_fsm_idle;
191	          end if;
192	        when axi_fsm_wr_data =>
193	          if ((axi_wlast = '1') and (s_axi_wvalid = '1')) then
194	            axi_fsm_comb <= axi_fsm_wr_resp_delay;
195	          end if;
196	        when axi_fsm_wr_resp_delay =>
197	          axi_fsm_comb <= axi_fsm_wr_done;
198	        when axi_fsm_wr_done =>
199	          if (s_axi_bready = '1') then
200	            axi_fsm_comb <= axi_fsm_idle;
201	          end if;
202	        when others =>
203	          axi_fsm_comb <= axi_fsm_idle;
204	      end case;
205	    end if;
206	  end process;
207	
208	  axi_fsm_proc : process(s_axi_aclk)
209	  begin
210	    if rising_edge(s_axi_aclk) then
211	      axi_fsm <= axi_fsm_comb;
212	    end if;
213	  end process axi_fsm_proc;
214	
215	  -----------------------------------------------------------------------------
216	  -- AXI ARADDR
217	  -----------------------------------------------------------------------------
218	  axi_arwrap_en <= '1' when ((axi_araddr and axi_arwrap) = axi_arwrap) else '0';
219	
220	  axi_araddr_proc : process(s_axi_aclk)
221	  begin
222	    if rising_edge(s_axi_aclk) then
223	      case axi_fsm is
224	        when axi_fsm_idle =>
225	          axi_rresp <= RESP_OKAY_c;
226	          if (axi_fsm_comb = axi_fsm_rd_data) then
227	            axi_araddr      <= unsigned(s_axi_araddr);
228	            axi_araddr_last <= unsigned(s_axi_araddr);
229	            case (s_axi_arsize) is
230	              when "000" =>
231	                axi_arsize <= to_unsigned(1, axi_addr_width_g);
232	              when "001" =>
233	                axi_arsize <= to_unsigned(2, axi_addr_width_g);
234	              when "010" =>
235	                axi_arsize <= to_unsigned(4, axi_addr_width_g);
236	              when "011" =>
237	                axi_arsize <= to_unsigned(8, axi_addr_width_g);
238	              when others =>
239	                axi_arsize <= to_unsigned(1, axi_addr_width_g);
240	            end case;
241	            axi_arburst     <= s_axi_arburst;
242	            axi_arlen       <= unsigned(s_axi_arlen);
243	            if (s_axi_arburst = "10") then -- If wrapping burst
244	              case (s_axi_arlen) is
245	                when X"01" =>
246	                  case (s_axi_arsize) is
247	                    when "000" =>
248	                      axi_arwrap <= to_unsigned(2 * 1 - 1, axi_addr_width_g);
249	                    when "001" =>
250	                      axi_arwrap <= to_unsigned(2 * 2 - 1, axi_addr_width_g);
251	                    when "010" =>
252	                      axi_arwrap <= to_unsigned(2 * 4 - 1, axi_addr_width_g);
253	                    when "011" =>
254	                      axi_arwrap <= to_unsigned(2 * 8 - 1, axi_addr_width_g);
255	                    when others =>
256	                      axi_arwrap <= to_unsigned(2 * 1 - 1, axi_addr_width_g);
257	                  end case;
258	                when X"03" =>
259	                  case (s_axi_arsize) is
260	                    when "000" =>
261	                      axi_arwrap <= to_unsigned(4 * 1 - 1, axi_addr_width_g);
262	                    when "001" =>
263	                      axi_arwrap <= to_unsigned(4 * 2 - 1, axi_addr_width_g);
264	                    when "010" =>
265	                      axi_arwrap <= to_unsigned(4 * 4 - 1, axi_addr_width_g);
266	                    when "011" =>
267	                      axi_arwrap <= to_unsigned(4 * 8 - 1, axi_addr_width_g);
268	                    when others =>
269	                      axi_arwrap <= to_unsigned(4 * 1 - 1, axi_addr_width_g);
270	                  end case;
271	                when X"07" =>
272	                  case (s_axi_arsize) is
273	                    when "000" =>
274	                      axi_arwrap <= to_unsigned(8 * 1 - 1, axi_addr_width_g);
275	                    when "001" =>
276	                      axi_arwrap <= to_unsigned(8 * 2 - 1, axi_addr_width_g);
277	                    when "010" =>
278	                      axi_arwrap <= to_unsigned(8 * 4 - 1, axi_addr_width_g);
279	                    when "011" =>
280	                      axi_arwrap <= to_unsigned(8 * 8 - 1, axi_addr_width_g);
281	                    when others =>
282	                      axi_arwrap <= to_unsigned(8 * 1 - 1, axi_addr_width_g);
283	                  end case;
284	                when X"0F" =>
285	                  case (s_axi_arsize) is
286	                    when "000" =>
287	                      axi_arwrap <= to_unsigned(16 * 1 - 1, axi_addr_width_g);
288	                    when "001" =>
289	                      axi_arwrap <= to_unsigned(16 * 2 - 1, axi_addr_width_g);
290	                    when "010" =>
291	                      axi_arwrap <= to_unsigned(16 * 4 - 1, axi_addr_width_g);
292	                    when "011" =>
293	                      axi_arwrap <= to_unsigned(16 * 8 - 1, axi_addr_width_g);
294	                    when others =>
295	                      axi_arwrap <= to_unsigned(16 * 1 - 1, axi_addr_width_g);
296	                  end case;
297	                when others =>
298	                  axi_arwrap <= to_unsigned(2 * 1 - 1, axi_addr_width_g);
299	              end case;
300	            end if;
301	          end if;
302	        when axi_fsm_rd_data =>
303	          -- Produce decoding error if memory is accessed but not enabled
304	          if unsigned(axi_araddr) >= (num_reg_g * 8) and not use_mem_g then
305	            axi_rresp <= RESP_DECERR_c;
306	          end if;
307	          -- Do access
308	          if (rpl_rready = '1') then
309	            case (axi_arburst) is
310	              when "00" =>              -- Fixed burst
311	                null;
312	              when "01" =>              -- Incremental burst
313	                axi_araddr <= axi_araddr + axi_arsize;
314	              when "10" =>              -- Wrapping burst
315	                if (axi_arwrap_en = '1') then
316	                  axi_araddr <= axi_araddr - axi_arwrap;
317	                else
318	                  axi_araddr <= axi_araddr + axi_arsize;
319	                end if;
320	              when others =>            -- Reserved
321	                null;
322	            end case;
323	            axi_araddr_last <= axi_araddr;
324	          else
325	            axi_araddr <= axi_araddr_last;
326	          end if;
327	          if (axi_rvalid = '1') then
328	            axi_arlen <= axi_arlen - 1;
329	          end if;
330	        when others =>
331	          null;
332	      end case;
333	    end if;
334	  end process axi_araddr_proc;
335	
336	  -----------------------------------------------------------------------------
337	  -- AXI RADDR denotes register or memory
338	  -----------------------------------------------------------------------------
339	  axi_raddr_sel <= '1' when ((axi_fsm = axi_fsm_rd_data) and (to_integer(unsigned(axi_araddr_last(axi_addr_width_g - 1 downto REG_ADDR_WIDTH))) /= 0)) else '0';
340	
341	  -----------------------------------------------------------------------------
342	  -- AXI ARREADY
343	  -----------------------------------------------------------------------------
344	  s_axi_arready <= '1' when ((axi_fsm = axi_fsm_idle) and (axi_fsm_comb = axi_fsm_rd_data)) else '0';
345	
346	  -----------------------------------------------------------------------------
347	  -- AXI RID
348	  -----------------------------------------------------------------------------
349	  axi_rid_proc : process(s_axi_aclk)
350	  begin
351	    if rising_edge(s_axi_aclk) then
352	      if (axi_fsm = axi_fsm_idle) then
353	        if (axi_fsm_comb = axi_fsm_rd_data) then
354	          axi_arid <= s_axi_arid;
355	        else
356	          axi_arid <= (others => '0');
357	        end if;
358	      end if;
359	    end if;
360	  end process axi_rid_proc;
361	
362	  rpl_rid <= axi_arid;
363	
364	  -----------------------------------------------------------------------------
365	  -- AXI RREADY
366	  -----------------------------------------------------------------------------
367	  axi_rready_proc : process(s_axi_aclk)
368	  begin
369	    if rising_edge(s_axi_aclk) then
370	      if (axi_fsm = axi_fsm_rd_data) then
371	        axi_rready <= rpl_rready;
372	      else
373	        axi_rready <= '0';
374	      end if;
375	    end if;
376	  end process axi_rready_proc;
377	
378	  -----------------------------------------------------------------------------
379	  -- AXI RVALID
380	  -----------------------------------------------------------------------------
381	  axi_rvalid <= reg_rvalid or mem_rvalid;
382	  rpl_rvalid <= axi_rvalid;
383	
384	  -----------------------------------------------------------------------------
385	  -- AXI RLAST
386	  -----------------------------------------------------------------------------
387	  axi_rlast <= '1' when (((mem_rvalid = '1') or (reg_rvalid = '1')) and (axi_arlen = X"00")) else '0';
388	  rpl_rlast <= axi_rlast;
389	
390	  -----------------------------------------------------------------------------
391	  -- AXI RRESP
392	  -----------------------------------------------------------------------------
393	  rpl_rresp <= axi_rresp;
394	
395	  -----------------------------------------------------------------------------
396	  -- AXI AWADDR
397	  -----------------------------------------------------------------------------
398	  axi_awwrap_en <= '1' when ((axi_awaddr and axi_awwrap) = axi_awwrap) else '0';
399	
400	  axi_awaddr_proc : process(s_axi_aclk)
401	  begin
402	    if rising_edge(s_axi_aclk) then
403	      case axi_fsm is
404	        when axi_fsm_idle =>
405	          axi_bresp <= RESP_OKAY_c;
406	          if (axi_fsm_comb = axi_fsm_wr_data) then
407	            axi_awaddr  <= unsigned(s_axi_awaddr);
408	            case (s_axi_awsize) is
409	              when "000" =>
410	                axi_awsize <= to_unsigned(1, axi_addr_width_g);
411	              when "001" =>
412	                axi_awsize <= to_unsigned(2, axi_addr_width_g);
413	              when "010" =>
414	                axi_awsize <= to_unsigned(4, axi_addr_width_g);
415	              when "011" =>
416	                axi_awsize <= to_unsigned(8, axi_addr_width_g);
417	              when others =>
418	                axi_awsize <= to_unsigned(1, axi_addr_width_g);
419	            end case;
420	            axi_awburst <= s_axi_awburst;
421	            axi_awlen   <= unsigned(s_axi_awlen);
422	            if (s_axi_awburst = "10") then -- If wrapping burst
423	              case (s_axi_awlen) is
424	                when X"01" =>
425	                  case (s_axi_awsize) is
426	                    when "000" =>
427	                      axi_awwrap <= to_unsigned(2 * 1 - 1, axi_addr_width_g);
428	                    when "001" =>
429	                      axi_awwrap <= to_unsigned(2 * 2 - 1, axi_addr_width_g);
430	                    when "010" =>
431	                      axi_awwrap <= to_unsigned(2 * 4 - 1, axi_addr_width_g);
432	                    when "011" =>
433	                      axi_awwrap <= to_unsigned(2 * 8 - 1, axi_addr_width_g);
434	                    when others =>
435	                      axi_awwrap <= to_unsigned(2 * 1 - 1, axi_addr_width_g);
436	                  end case;
437	                when X"03" =>
438	                  case (s_axi_awsize) is
439	                    when "000" =>
440	                      axi_awwrap <= to_unsigned(4 * 1 - 1, axi_addr_width_g);
441	                    when "001" =>
442	                      axi_awwrap <= to_unsigned(4 * 2 - 1, axi_addr_width_g);
443	                    when "010" =>
444	                      axi_awwrap <= to_unsigned(4 * 4 - 1, axi_addr_width_g);
445	                    when "011" =>
446	                      axi_awwrap <= to_unsigned(4 * 8 - 1, axi_addr_width_g);
447	                    when others =>
448	                      axi_awwrap <= to_unsigned(4 * 1 - 1, axi_addr_width_g);
449	                  end case;
450	                when X"07" =>
451	                  case (s_axi_awsize) is
452	                    when "000" =>
453	                      axi_awwrap <= to_unsigned(8 * 1 - 1, axi_addr_width_g);
454	                    when "001" =>
455	                      axi_awwrap <= to_unsigned(8 * 2 - 1, axi_addr_width_g);
456	                    when "010" =>
457	                      axi_awwrap <= to_unsigned(8 * 4 - 1, axi_addr_width_g);
458	                    when "011" =>
459	                      axi_awwrap <= to_unsigned(8 * 8 - 1, axi_addr_width_g);
460	                    when others =>
461	                      axi_awwrap <= to_unsigned(8 * 1 - 1, axi_addr_width_g);
462	                  end case;
463	                when X"0F" =>
464	                  case (s_axi_awsize) is
465	                    when "000" =>
466	                      axi_awwrap <= to_unsigned(16 * 1 - 1, axi_addr_width_g);
467	                    when "001" =>
468	                      axi_awwrap <= to_unsigned(16 * 2 - 1, axi_addr_width_g);
469	                    when "010" =>
470	                      axi_awwrap <= to_unsigned(16 * 4 - 1, axi_addr_width_g);
471	                    when "011" =>
472	                      axi_awwrap <= to_unsigned(16 * 8 - 1, axi_addr_width_g);
473	                    when others =>
474	                      axi_awwrap <= to_unsigned(16 * 1 - 1, axi_addr_width_g);
475	                  end case;
476	                when others =>
477	                  axi_awwrap <= to_unsigned(2 * 1 - 1, axi_addr_width_g);
478	              end case;
479	            end if;
480	          end if;
481	        when axi_fsm_wr_data =>
482	          -- Produce decoding error if memory is accessed but not enabled
483	          if unsigned(axi_awaddr) >= (num_reg_g * 8) and not use_mem_g then
484	            axi_bresp <= RESP_DECERR_c;
485	          end if;
486	          -- Do access
487	          if (s_axi_wvalid = '1') then
488	            case (axi_awburst) is
489	              when "00" =>              -- Fixed burst
490	                null;
491	              when "01" =>              -- Incremental burst
492	                axi_awaddr <= axi_awaddr + axi_awsize;
493	              when "10" =>              -- Wrapping burst
494	                if (axi_awwrap_en = '1') then
495	                  axi_awaddr <= axi_awaddr - axi_awwrap;
496	                else
497	                  axi_awaddr <= axi_awaddr + axi_awsize;
498	                end if;
499	              when others =>            -- Reserved
500	                null;
501	            end case;
502	          end if;
503	          if (axi_wready = '1') then
504	            axi_awlen <= axi_awlen - 1;
505	          end if;
506	        when others =>
507	          null;
508	      end case;
509	    end if;
510	  end process axi_awaddr_proc;
511	
512	  -----------------------------------------------------------------------------
513	  -- AXI WADDR denotes register or memory
514	  -----------------------------------------------------------------------------
515	  axi_waddr_sel <= '1' when ((axi_fsm = axi_fsm_wr_data) and (to_integer(unsigned(axi_awaddr(axi_addr_width_g - 1 downto REG_ADDR_WIDTH))) /= 0)) else '0';
516	
517	  -----------------------------------------------------------------------------
518	  -- AXI AWREADY
519	  -----------------------------------------------------------------------------
520	  s_axi_awready <= '1' when ((axi_fsm = axi_fsm_idle) and (axi_fsm_comb = axi_fsm_wr_data)) else '0';
521	
522	  -----------------------------------------------------------------------------
523	  -- AXI WID
524	  -----------------------------------------------------------------------------
525	  axi_wid_proc : process(s_axi_aclk)
526	  begin
527	    if rising_edge(s_axi_aclk) then
528	      if (axi_fsm = axi_fsm_idle) then
529	        if (axi_fsm_comb = axi_fsm_wr_data) then
530	          axi_awid <= s_axi_awid;
531	        else
532	          axi_awid <= (others => '0');
533	        end if;
534	      end if;
535	    end if;
536	  end process axi_wid_proc;
537	
538	  s_axi_bid <= axi_awid;
539	
540	  -----------------------------------------------------------------------------
541	  -- AXI WREADY
542	  -----------------------------------------------------------------------------
543	  axi_wready   <= '1' when ((axi_fsm = axi_fsm_wr_data) and (s_axi_wvalid = '1')) else '0';
544	  s_axi_wready <= axi_wready;
545	
546	  -----------------------------------------------------------------------------
547	  -- AXI WLAST
548	  -----------------------------------------------------------------------------
549	  axi_wlast <= '1' when ((axi_wready = '1') and (axi_awlen = X"00")) else '0';
550	
551	  -----------------------------------------------------------------------------
552	  -- AXI BRESP
553	  -----------------------------------------------------------------------------
554	  s_axi_bresp <= axi_bresp;
555	
556	  -----------------------------------------------------------------------------
557	  -- AXI BVALID
558	  -----------------------------------------------------------------------------
559	  s_axi_bvalid <= '1' when (axi_fsm = axi_fsm_wr_done) else '0';
560	
561	  ---------------------------------------------------------------------------
562	  -- IP to Bus data
563	  ---------------------------------------------------------------------------
564	  rpl_rdata <= reg_rdata when (reg_rvalid = '1')
565	               else i_mem_rdata when (mem_rvalid = '1' and use_mem_g)
566	               else (others => '0');
567	
568	  ---------------------------------------------------------------------------
569	  -- Register read
570	  ---------------------------------------------------------------------------
571	  reg_rvalid <= '1' when ((axi_raddr_sel = '0') and (axi_fsm = axi_fsm_rd_data) and (axi_rready = '1') and (rpl_rready = '1')) else '0';
572	
573	  b_rdreg : block
574	    signal rd_data_ext : t_aslv64(0 to num_reg_g + 1) := (others => (others => '0'));
575	  begin
576	    rd_data_ext(0 to i_reg_rdata'high) <= i_reg_rdata; -- extend number of registers to prevent indexing errors
577	    reg_rdata_proc : process(s_axi_aclk) is
578	    begin
579	      if rising_edge(s_axi_aclk) then
580	        reg_rdata(axi_data_width_g - 1 downto 0) <= rd_data_ext(to_integer(unsigned(axi_araddr(REG_ADDR_INDEX_HIGH downto REG_ADDR_INDEX_LOW))));
581	      end if;
582	    end process reg_rdata_proc;
583	  end block;
584	
585	  reg_rd_proc : process(s_axi_aclk) is
586	  begin
587	    if rising_edge(s_axi_aclk) then
588	      if (s_axi_aresetn = '0') then
589	        reg_rd <= (others => '0');
590	      else
591	        reg_rd <= (others => '0');
592	        if (reg_rvalid = '1') then
593	          reg_rd(to_integer(unsigned(axi_araddr_last(REG_ADDR_INDEX_HIGH downto REG_ADDR_INDEX_LOW)))) <= '1';
594	        end if;
595	      end if;
596	    end if;
597	  end process reg_rd_proc;
598	
599	  o_reg_rd <= reg_rd;
600	
601	  ---------------------------------------------------------------------------
602	  -- Register write
603	  ---------------------------------------------------------------------------
604	  reg_wr_proc : process(s_axi_aclk) is
605	  begin
606	    if rising_edge(s_axi_aclk) then
607	      if (s_axi_aresetn = '0') then
608	        reg_wr <= (others => '0');
609	      else
610	        reg_wr <= (others => '0');
611	        if ((axi_waddr_sel = '0') and (axi_wready = '1')) then
612	          reg_wr(to_integer(unsigned(axi_awaddr(REG_ADDR_INDEX_HIGH downto REG_ADDR_INDEX_LOW)))) <= '1';
613	        end if;
614	      end if;
615	    end if;
616	  end process reg_wr_proc;
617	
618	  o_reg_wr <= reg_wr;
619	
620	  slv_reg_wr_proc : process(s_axi_aclk) is
621	  begin
622	    if rising_edge(s_axi_aclk) then
623	      if (s_axi_aresetn = '0') then
624	        o_reg_wdata                  <= (others => (others => '0'));
625	        o_reg_wdata(rst_val_g'range) <= rst_val_g;
626	      else
627	        for reg_byte_index in 0 to axi_byte_width_g - 1 loop
628	          if ((axi_waddr_sel = '0') and (axi_wready = '1') and (s_axi_wstrb(reg_byte_index) = '1')) then
629	            o_reg_wdata(to_integer(unsigned(axi_awaddr(REG_ADDR_INDEX_HIGH downto REG_ADDR_INDEX_LOW))))(reg_byte_index * 8 + 7 downto reg_byte_index * 8) <= s_axi_wdata(reg_byte_index * 8 + 7 downto reg_byte_index * 8);
630	          end if;
631	        end loop;
632	      end if;
633	    end if;
634	  end process slv_reg_wr_proc;
635	
636	  -----------------------------------------------------------------------------
637	  -- Memory read/write
638	  -----------------------------------------------------------------------------
639	  mem_rvalid <= '1' when ((axi_raddr_sel = '1') and (axi_fsm = axi_fsm_rd_data) and (axi_rready = '1') and (rpl_rready = '1')) else '0';
640	  g_mem : if use_mem_g generate
641	    o_mem_addr  <= std_logic_vector(axi_awaddr - MEM_ADDR_START) when (axi_waddr_sel = '1') else std_logic_vector(axi_araddr - MEM_ADDR_START);
642	    g_o_mem_wr : for reg_byte_index in 0 to axi_byte_width_g - 1 generate
643	      o_mem_wr(reg_byte_index) <= '1' when ((axi_waddr_sel = '1') and (axi_fsm = axi_fsm_wr_data) and (s_axi_wvalid = '1') and (s_axi_wstrb(reg_byte_index) = '1')) else '0';
644	    end generate;
645	    o_mem_wdata <= s_axi_wdata;
646	  end generate;
647	  g_nmem : if not use_mem_g generate
648	    o_mem_wr    <= (others => '0');
649	    o_mem_wdata <= (others => '0');
650	    o_mem_addr  <= (others => '0');
651	  end generate;
652	
653	  -----------------------------------------------------------------------------
654	  -- R-Channel Pipeline Stage
655	  -----------------------------------------------------------------------------
656	  -- The logic (ported legacy code) does only assert RVALID after RREADY is present. This violates the AXI specification.
657	  -- By using a pipeline stage to decouple the logic from the bus, this problem can be solved (the PL stage always asserts READY).
658	  b_rplstage : block
659	    signal pl_in_data  : std_logic_vector(axi_id_width_g + axi_data_width_g + 3 - 1 downto 0);
660	    signal pl_out_data : std_logic_vector(pl_in_data'range);
661	  begin
662	    pl_in_data(axi_data_width_g - 1 downto 0)                                         <= rpl_rdata;
663	    pl_in_data(axi_data_width_g + 2 - 1 downto axi_data_width_g)                      <= rpl_rresp;
664	    pl_in_data(axi_data_width_g + 2)                                                  <= rpl_rlast;
665	    pl_in_data(axi_id_width_g + axi_data_width_g + 3 - 1 downto axi_data_width_g + 3) <= rpl_rid;
666	
667	    i_rplstage : entity work.psi_common_pl_stage
668	      generic map(
669	        width_g => axi_id_width_g + axi_data_width_g + 3,
670	        use_rdy_g => true,
671	        rst_pol_g => '0'
672	      )
673	      port map(
674	        clk_i => s_axi_aclk,
675	        rst_i => s_axi_aresetn,
676	        vld_i => rpl_rvalid,
677	        rdy_o => rpl_rready,
678	        dat_i => pl_in_data,
679	        -- Output
680	        vld_o => s_axi_rvalid,
681	        rdy_i => s_axi_rready,
682	        dat_o => pl_out_data
683	      );
684	
685	    s_axi_rdata <= pl_out_data(axi_data_width_g - 1 downto 0);
686	    s_axi_rresp <= pl_out_data(axi_data_width_g + 2 - 1 downto axi_data_width_g);
687	    s_axi_rlast <= pl_out_data(axi_data_width_g + 2);
688	    s_axi_rid   <= pl_out_data(axi_id_width_g + axi_data_width_g + 3 - 1 downto axi_data_width_g + 3);
689	  end block;
690	
691	end architecture;

